// French facts loaded before the main Oracle app.
const FACTS_FR=[
  {id:'s1',cat:'science',text:"Un éclair chauffe l'air environnant à une température cinq fois supérieure à la surface du Soleil — environ 30 000 °C."},
  {id:'s2',cat:'science',text:"93 % de la masse de ton corps est de la poussière d'étoile : les atomes qui te composent ont été forgés dans des soleils disparus il y a des milliards d'années."},
  {id:'s3',cat:'science',text:"Les oiseaux migrateurs voient littéralement les lignes du champ magnétique terrestre superposées à leur vision, comme une boussole intégrée dans les yeux."},
  {id:'s4',cat:'science',text:"Dans une seule cuillère à café de terre, il y a plus de micro-organismes que d'êtres humains sur toute la planète."},
  {id:'s5',cat:'science',text:"Certains rapaces australiens déclenchent délibérément des incendies en transportant des braises dans leurs serres pour faire fuir leurs proies."},
  {id:'s6',cat:'science',text:"Il existe des icebergs rayés de vert : quand un iceberg absorbe de l'eau de mer, les algues colorent ses strates de l'intérieur."},
  {id:'s7',cat:'science',text:"La moitié de l'oxygène que tu respires est produite par des micro-organismes planctoniques invisibles à l'œil nu dans les océans."},
  {id:'s8',cat:'science',text:"La foudre fossilisée existe : lorsqu'un éclair frappe du sable, il le vitrife instantanément en formant des tubes creux appelés fulgurites."},
  {id:'s9',cat:'science',text:"Le nombre d'arbres sur Terre — environ 3 000 milliards — dépasse le nombre d'étoiles dans la Voie Lactée."},
  {id:'s10',cat:'science',text:"Des virus nous « pleuvent » dessus depuis la stratosphère en permanence, transportés par les courants d'air à travers le globe."},
  {id:'s11',cat:'science',text:"Certains arbres communiquent via un réseau de champignons souterrains — les scientifiques l'appellent l'« internet des forêts »."},
  {id:'s12',cat:'science',text:"L'eau chaude peut geler plus vite que l'eau froide dans certaines conditions — c'est l'effet Mpemba, connu depuis l'Antiquité et encore débattu."},
  {id:'s13',cat:'science',text:"Le son voyage quinze fois plus vite dans l'acier que dans l'air."},
  {id:'p1',cat:'positive',text:"La tortue verte marine est officiellement passée en 2025 dans la catégorie préoccupation mineure — ses populations ont augmenté de 28 % depuis 1970."},
  {id:'p2',cat:'positive',text:"Pour la première fois, le monde a produit plus d'électricité via les énergies renouvelables que via le charbon durant le premier semestre 2025."},
  {id:'p3',cat:'positive',text:"Le nombre mondial de décès liés à la pollution de l'air a été réduit de moitié depuis 1990."},
  {id:'p4',cat:'positive',text:"La couche d'ozone se régénère depuis l'interdiction des CFC dans les années 1980 — l'une des plus grandes réussites de la coopération internationale."},
  {id:'p5',cat:'positive',text:"En France, le nombre de décès prématurés liés aux particules fines a diminué de 47 % entre 2005 et 2022."},
  {id:'p6',cat:'positive',text:"La Terre a gagné 5 % de surface verte entre 2000 et 2017 — l'équivalent d'une forêt amazonienne entière."},
  {id:'p7',cat:'positive',text:"Le Royaume-Uni a fermé sa dernière centrale à charbon en 2024, devenant le premier pays du G7 à éliminer totalement cette source d'énergie."},
  {id:'p8',cat:'positive',text:"Des chercheurs britanniques ont réussi en 2025 à ralentir la progression de la maladie de Huntington grâce à la thérapie génique."},
  {id:'p9',cat:'positive',text:"La France a créé en 2025 la plus grande aire marine protégée de la planète, en Polynésie française."},
  {id:'p10',cat:'positive',text:"Le taux de mortalité infantile mondiale a chuté de 60 % depuis 1990, sauvant des millions de vies chaque année."},
  {id:'p11',cat:'positive',text:"Le paludisme a été réduit de 76 % dans les pays les plus touchés grâce aux moustiquaires imprégnées et aux antipaludéens — épargnant plus de 7 millions de vies depuis 2000."},
  {id:'p12',cat:'positive',text:"Le coût de l'énergie solaire a chuté de 90 % en dix ans. En 2023, c'est la source d'électricité la moins chère de l'histoire de l'humanité dans la plupart des régions du monde."},
  {id:'p13',cat:'positive',text:"La baleine à bosse, autrefois au bord de l'extinction à cause de la chasse commerciale, est désormais classée « préoccupation mineure » par l'UICN — sa population mondiale a rebondi de plus de 93 %."},
  {id:'p14',cat:'positive',text:"En 1990, 36 % de la population mondiale vivait dans l'extrême pauvreté. En 2024, ce chiffre est tombé sous les 9 % — une réduction sans précédent dans l'histoire humaine."},
  {id:'p15',cat:'positive',text:"La variole a été officiellement éradiquée en 1980 grâce à une campagne de vaccination mondiale coordonnée par l'OMS — c'est la seule maladie humaine jamais totalement éliminée par l'action humaine."},
  {id:'p16',cat:'positive',text:"Le couvert forestier mondial a augmenté dans certaines régions d'Europe et d'Asie grâce aux efforts de reboisement — la France a gagné 30 % de forêt supplémentaire depuis 1950."},
  {id:'p17',cat:'positive',text:"En 2023, 73 % de la population mondiale a accès à de l'eau potable gérée en toute sécurité — contre seulement 59 % en 2000, représentant plus d'un milliard de personnes supplémentaires."},
  {id:'p18',cat:'positive',text:"Les ventes mondiales de véhicules électriques ont dépassé 14 millions d'unités en 2023, représentant 18 % des voitures neuves vendues — une multiplication par 60 en moins de dix ans."},
  {id:'p19',cat:'positive',text:"Le nombre d'espèces animales sauvages suivies par le WWF a augmenté de 4 % depuis 2020 dans les zones protégées, grâce aux efforts de conservation ciblés sur les espèces menacées prioritaires."},
  {id:'p20',cat:'positive',text:"La proportion de la population mondiale souffrant de la faim a été réduite de moitié depuis les années 1990. En 2023, l'ONU estime qu'un million d'enfants de moins ont souffert de malnutrition sévère qu'en 2020."},
  {id:'u1',cat:'fun',text:"Les bananes sont naturellement radioactives. Il faudrait en manger dix milliards d'un coup pour atteindre une dose dangereuse — et tu mourrais d'autre chose avant."},
  {id:'u2',cat:'fun',text:"Une blatte peut survivre une semaine entière après avoir été décapitée — elle ne meurt pas de perdre la tête, mais de soif, sans bouche pour boire."},
  {id:'u3',cat:'fun',text:"La lettre J est la seule absente du tableau périodique des éléments chimiques."},
  {id:'u4',cat:'fun',text:"L'oxygène liquide est bleu pâle — le gaz incolore que tu respires prend une teinte azurée dès qu'il change d'état."},
  {id:'u5',cat:'fun',text:"Un champignon parasite appelé Ophiocordyceps prend le contrôle du cerveau d'une fourmi, la force à grimper sur une plante, puis la tue pour se reproduire."},
  {id:'u6',cat:'fun',text:"L'acide gastrique humain a un pH entre 1 et 2 — aussi agressif que l'acide d'une batterie de voiture — et ton estomac s'en sort très bien."},
  {id:'u7',cat:'fun',text:"Il y a plus d'étoiles dans l'univers observable que de grains de sable sur toutes les plages et déserts de la Terre réunis."},
  {id:'u8',cat:'fun',text:"Le venin de la pieuvre à anneaux bleus peut tuer 26 personnes adultes en quelques minutes — et il n'existe aucun antidote."},
  {id:'u9',cat:'fun',text:"Il y a environ 100 milliards de bactéries dans ta bouche en ce moment, et 25 000 germes sur chaque centimètre carré de ton téléphone."},
  {id:'u10',cat:'fun',text:"Un iceberg contient plus d'énergie thermique totale qu'une allumette allumée — parce que l'énergie dépend de la masse, pas de la température."},
  {id:'u11',cat:'fun',text:"Le point qui surmonte les lettres i et j a un nom : le « tittle ». Sans lui, ces lettres seraient confondues avec d'autres dans les manuscrits médiévaux."},
  {id:'u12',cat:'fun',text:"Les chimpanzés sont meilleurs que les humains pour mémoriser des suites de chiffres affichées pendant une fraction de seconde — leur mémoire photographique de travail surpasse la nôtre."},
  {id:'u13',cat:'fun',text:"Des scientifiques ont créé en 2022 un enzyme capable de dégrader le plastique PET en quelques heures, là où la nature met des siècles."},
  {id:'u14',cat:'fun',text:"Des chercheurs ont démontré que les chats reconnaissent leur propre prénom — mais choisissent délibérément de ne pas répondre à l'appel de leur maître, contrairement aux chiens."},
  {id:'u15',cat:'fun',text:"Un groupe de flamants roses est appelé une « flamboyance ». Ces oiseaux sont naturellement blancs : leur couleur rose provient des pigments caroténoïdes contenus dans les crevettes et algues qu'ils mangent."},
  {id:'u16',cat:'fun',text:"Le poisson-pistolet émet des clics à 160 décibels pour assommer ses proies — le son le plus fort produit par un animal par rapport à sa taille dans tout le règne animal."},
  {id:'u17',cat:'fun',text:"La crevette mante peut frapper avec une force équivalente à une balle de pistolet à 23 m/s — ses coups créent des bulles de cavitation qui atteignent 4 000 °C à l'impact."},
  {id:'u18',cat:'fun',text:"Le pet d'un hareng leur sert à communiquer : ils expulsent des bulles par l'anus pour maintenir le contact avec leurs congénères dans l'obscurité. Cette découverte a valu à ses auteurs le prix Ig Nobel."},
  {id:'u19',cat:'fun',text:"Le nombril humain abrite en moyenne 67 espèces de bactéries différentes. Dans un cas documenté, des chercheurs ont trouvé une bactérie jusqu'alors répertoriée uniquement au Japon — chez un homme n'y ayant jamais mis les pieds."},
  {id:'u20',cat:'fun',text:"La vitesse à laquelle un homard fuit un prédateur est plus rapide que celle à laquelle il nage normalement — il se propulse à reculons en battant de la queue à une vitesse pouvant dépasser 5 mètres par seconde."},
  {id:'h1',cat:'history',text:"Les Romains utilisaient de l'urine humaine comme dentifrice et pour blanchir leurs vêtements — l'ammoniaque qu'elle contient est effectivement un détachant naturel."},
  {id:'h2',cat:'history',text:"Cléopâtre a vécu plus près de nous dans le temps que de la construction des pyramides de Gizeh — elle en était séparée de 2 500 ans, nous de seulement 2 000 ans."},
  {id:'h3',cat:'history',text:"Le feu grégeois, arme secrète de l'Empire Byzantin, brûlait même sur l'eau — sa composition exacte reste un mystère non élucidé à ce jour."},
  {id:'h4',cat:'history',text:"Les Vikings utilisaient une « pierre solaire » — la calcite islandaise — pour naviguer par temps nuageux en localisant le Soleil caché."},
  {id:'h5',cat:'history',text:"Oxford est plus ancienne que les Aztèques : l'université a commencé ses cours vers 1096, soit 300 ans avant la fondation de Tenochtitlán."},
  {id:'h6',cat:'history',text:"Le Colisée romain pouvait être partiellement inondé pour des batailles navales miniatures — des naumachies en plein cœur de Rome."},
  {id:'h7',cat:'history',text:"Les gladiateurs romains étaient majoritairement végétariens : leur régime à base d'orge et de légumineuses leur valait le surnom de « mangeurs d'orge »."},
  {id:'h8',cat:'history',text:"La bibliothèque d'Alexandrie n'a pas été détruite en une seule catastrophe — elle a décliné progressivement sur plusieurs siècles."},
  {id:'h9',cat:'history',text:"Napoléon mesurait 1m69, dans la moyenne haute pour l'époque — la légende de sa petite taille vient d'une confusion entre mesures françaises et anglaises."},
  {id:'h10',cat:'history',text:"La guerre la plus courte de l'histoire — le Royaume-Uni contre Zanzibar en 1896 — a duré exactement 38 minutes."},
  {id:'h11',cat:'history',text:"Les pyramides n'ont pas été construites par des esclaves, mais par des ouvriers libres, payés, nourris et logés — des papyrus en attestent."},
  {id:'h12',cat:'history',text:"Il y a plus de pyramides au Soudan (environ 200) qu'en Égypte (environ 130) — les pyramides nubiennes de Méroé sont bien moins connues mais tout aussi impressionnantes."},
  {id:'sp1',cat:'space',text:"Un jour sur Vénus est plus long qu'une année sur Vénus — la planète tourne si lentement sur elle-même que le Soleil y lève à l'ouest."},
  {id:'sp2',cat:'space',text:"Saturne est si peu dense qu'elle flotterait sur l'eau si on trouvait un océan suffisamment grand pour l'y poser."},
  {id:'sp3',cat:'space',text:"La lumière que tu vois en regardant le Soleil a mis 100 000 ans à remonter de son cœur jusqu'à sa surface — puis seulement 8 minutes pour arriver jusqu'à toi."},
  {id:'sp4',cat:'space',text:"La sonde Voyager 1, lancée en 1977, est à plus de 23 milliards de kilomètres — elle émet encore des signaux que nous recevons."},
  {id:'sp5',cat:'space',text:"Mars possède le plus grand volcan du système solaire : l'Olympus Mons culmine à 22 km — trois fois l'Everest — sur une base aussi large que la France."},
  {id:'sp6',cat:'space',text:"Il tombe de la neige sur Mars — mais elle est composée de CO₂ et se sublime avant d'atteindre le sol, disparaissant comme par magie en plein vol."},
  {id:'sp7',cat:'space',text:"La Lune s'éloigne de la Terre de 3,8 cm chaque année — dans quelques milliards d'années, les éclipses totales de Soleil n'existeront plus."},
  {id:'sp8',cat:'space',text:"L'espace sent la framboise brûlée et le rhum selon des astronomes qui ont analysé les molécules d'un nuage de gaz au cœur de notre galaxie."},
  {id:'sp9',cat:'space',text:"Une cuillère à café de matière d'étoile à neutrons pèserait environ un milliard de tonnes — soit à peu près le poids du mont Fuji."},
  {id:'sp10',cat:'space',text:"Les trous noirs ne « sucent » pas — ils exercent la même attraction gravitationnelle qu'une étoile de masse équivalente. C'est la proximité qui les rend mortels."},
  {id:'a1',cat:'animals',text:"Les pieuvres possèdent trois cœurs, du sang bleu et neuf cerveaux — un central et un par tentacule, chacun capable d'agir de façon autonome."},
  {id:'a2',cat:'animals',text:"Les dauphins ont des prénoms : ils développent un sifflement unique dès la naissance et se présentent les uns aux autres en l'utilisant."},
  {id:'a3',cat:'animals',text:"Le tardigrade peut survivre dans le vide de l'espace, à des températures proches du zéro absolu, et à des doses de radiation mortelles pour tout autre être vivant."},
  {id:'a4',cat:'animals',text:"Les corbeaux reconnaissent les visages humains et s'en souviennent pendant des années — ils peuvent même transmettre cette information à leurs congénères."},
  {id:'a5',cat:'animals',text:"Un escargot peut dormir jusqu'à trois ans d'affilée en entrant en hibernation pendant les périodes de sécheresse."},
  {id:'a6',cat:'animals',text:"La méduse Turritopsis dohrnii est biologiquement immortelle : quand elle vieillit ou est blessée, elle se transforme à nouveau en polype juvénile."},
  {id:'a7',cat:'animals',text:"Le pistol shrimp génère en claquant sa pince une bulle à 4 700 °C — brièvement plus chaude que la surface du Soleil."},
  {id:'a8',cat:'animals',text:"Les fourmis coupe-feuilles cultivent des champignons depuis 50 millions d'années — bien avant que l'agriculture humaine n'existe."},
  {id:'a9',cat:'animals',text:"Les vaches ont des meilleures amies et subissent un stress réel lorsqu'elles en sont séparées — leur rythme cardiaque augmente mesuralement."},
  {id:'a10',cat:'animals',text:"Les loutres de mer se tiennent la patte pendant qu'elles dorment pour ne pas dériver et se perdre dans le courant."},
  {id:'a11',cat:'animals',text:"Les papillons goûtent la nourriture avec leurs pattes — des récepteurs gustatifs leur permettent de savoir si une plante est comestible avant même de se poser."},
  {id:'a12',cat:'animals',text:"Les éléphants sont les seuls mammifères terrestres physiquement incapables de sauter — leur masse et leur squelette ne le permettent tout simplement pas."},
  {id:'a13',cat:'animals',text:"Le cœur d'une baleine bleue est si gros qu'un être humain pourrait nager dans ses artères principales."},
  {id:'a14',cat:'animals',text:"Les abeilles sont capables de reconnaître et mémoriser les visages humains — une capacité étonnante pour un insecte au cerveau de la taille d'un grain de sésame."},
  {id:'b1',cat:'body',text:"L'ADN contenu dans une seule de tes cellules mesure deux mètres de long ; celui de tout ton corps dépasse mille fois la distance Terre-Soleil."},
  {id:'b2',cat:'body',text:"Ton cerveau génère environ 70 000 pensées par jour et consomme 20 % de l'énergie totale du corps — alors qu'il ne représente que 2 % de ta masse."},
  {id:'b3',cat:'body',text:"Les os humains sont, en termes de résistance par unité de poids, plus solides que l'acier — un cube d'os de 2,5 cm peut supporter neuf tonnes."},
  {id:'b4',cat:'body',text:"Ton estomac fabrique un nouveau revêtement muqueux toutes les deux semaines — sinon, il se digérerait lui-même avec l'acide qu'il produit."},
  {id:'b5',cat:'body',text:"Le cœur humain génère assez de pression pour projeter du sang à huit mètres de hauteur — et il bat 100 000 fois par jour sans jamais se reposer."},
  {id:'b6',cat:'body',text:"Les cornées des yeux sont les seuls tissus du corps humain qui ne reçoivent pas de sang — elles absorbent l'oxygène directement depuis les larmes et l'air."},
  {id:'b7',cat:'body',text:"Le foie est le seul organe humain capable de se régénérer complètement à partir de seulement 25 % de sa masse d'origine."},
  {id:'b8',cat:'body',text:"Tu es environ 1 cm plus grand le matin que le soir — la compression progressive des cartilages intervertébraux au fil de la journée en est la cause."},
  {id:'b9',cat:'body',text:"Les bébés naissent avec environ 300 os, mais certains fusionnent au fil de la croissance — un adulte n'en conserve que 206."},
  {id:'b10',cat:'body',text:"Il est impossible de se chatouiller soi-même : le cerveau anticipe la sensation et annule le signal avant même qu'il n'atteigne la conscience."},
  {id:'ar1',cat:'arts',text:"Salvador Dalí dessinait souvent au dos de ses chèques au restaurant, sachant que les propriétaires ne les encaisseraient jamais pour conserver l'œuvre originale."},
  {id:'ar2',cat:'arts',text:"La Joconde n'a pas de sourcils — c'était la mode à la Renaissance de se les raser totalement."},
  {id:'ar3',cat:'arts',text:"Victor Hugo a écrit la majeure partie de ses œuvres, dont Les Misérables, debout sur un pupitre."},
  {id:'ar4',cat:'arts',text:"Le film Paranormal Activity a coûté 15 000 $ à produire et en a rapporté 193 millions — l'un des meilleurs retours sur investissement de l'histoire du cinéma."},
  {id:'ar5',cat:'arts',text:"Mozart a composé sa première symphonie à l'âge de 8 ans — et son père l'emmenait se produire devant les cours royales d'Europe depuis ses 6 ans."},
  {id:'ar6',cat:'arts',text:"Les statues de la Grèce antique n'étaient pas blanches — elles étaient peintes de couleurs vives. C'est le temps qui a effacé les pigments."},
  {id:'ar7',cat:'arts',text:"Michael Jackson a tenté de racheter Marvel dans les années 90 car il voulait absolument jouer le rôle de Spider-Man au cinéma."},
  {id:'ar8',cat:'arts',text:"La Tour Eiffel devait être démantelée 20 ans après sa construction — elle a été sauvée grâce à son utilité comme antenne pour les transmissions radio militaires."},
  {id:'ar9',cat:'arts',text:"La statuette des Oscars s'appelle « Oscar » car une bibliothécaire de l'Académie trouvait qu'elle ressemblait à son oncle du même prénom."},
  {id:'ar10',cat:'arts',text:"En 1911, Picasso a été arrêté et interrogé comme suspect dans le vol de la Joconde au Louvre."},
  {id:'ar11',cat:'arts',text:"C'est le vol de la Joconde en 1911 qui l'a rendue mondialement célèbre — avant cela, elle était peu connue du grand public."},
  {id:'ar12',cat:'arts',text:"Le jeu Minecraft est le jeu vidéo le plus vendu de l'histoire avec plus de 300 millions de copies — devant Tetris et GTA V."},
  {id:'ar13',cat:'arts',text:"Beethoven était sourd quand il a composé sa Neuvième Symphonie — il n'a jamais pu l'entendre."},
  {id:'inv1',cat:'inventions',text:"Le micro-ondes a été inventé par accident en 1945 quand un ingénieur a remarqué que son chocolat avait fondu dans sa poche près d'un radar."},
  {id:'inv2',cat:'inventions',text:"Le Post-it est né d'une colle ratée — Spencer Silver cherchait un adhésif ultra-puissant et a obtenu une colle si faible qu'elle collait indéfiniment mais sans force."},
  {id:'inv3',cat:'inventions',text:"La pénicilline a été découverte par Fleming parce qu'il était parti en vacances sans ranger ses boîtes de Petri."},
  {id:'inv4',cat:'inventions',text:"Le Velcro a été inventé après qu'un ingénieur suisse a remarqué des bardanes accrochées à sa veste — et examiné leurs crochets au microscope."},
  {id:'inv5',cat:'inventions',text:"Le Frisbee vient des plats à tarte métalliques d'une boulangerie américaine nommée « Frisbie Pie Company »."},
  {id:'inv6',cat:'inventions',text:"La technologie Wi-Fi a été développée grâce à des recherches sur les signaux radio des trous noirs — une technologie spatiale recyclée pour nos box internet."},
  {id:'inv7',cat:'inventions',text:"Le briquet a été inventé en 1823, soit trois ans avant l'invention de l'allumette à friction."},
  {id:'inv8',cat:'inventions',text:"Le premier ordinateur, ENIAC, pesait 30 tonnes et occupait une pièce entière de 167 m²."},
  {id:'inv9',cat:'inventions',text:"La tarte Tatin est née d'une erreur des sœurs Tatin qui ont oublié la pâte et l'ont rajoutée par-dessus les pommes déjà caramélisées."},
  {id:'inv10',cat:'inventions',text:"Les rayons X ont été découverts accidentellement en 1895 : Röntgen a remarqué qu'une plaque photographique brillait à distance à travers des objets opaques."},
  {id:'inv11',cat:'inventions',text:"Le papier bulle était initialement destiné à être un papier peint texturé en 3D — un flop commercial total recyclé en matériel d'emballage."},
  {id:'w1',cat:'world',text:"En Suisse, il est illégal de posséder un seul cochon d'Inde — la loi oblige à en avoir au moins deux, car l'isolement est considéré comme une maltraitance."},
  {id:'w2',cat:'world',text:"Le Canada possède plus de lacs que tous les autres pays du monde réunis — environ 60 % des lacs de la planète se trouvent sur son territoire."},
  {id:'w3',cat:'world',text:"En France, il est légalement permis d'épouser une personne décédée — sous certaines conditions et avec l'autorisation du Président de la République."},
  {id:'w4',cat:'world',text:"L'Australie est plus large que la Lune — le continent australien mesure 4 000 km d'est en ouest, tandis que le diamètre de la Lune n'est que de 3 474 km."},
  {id:'w5',cat:'world',text:"La Russie s'étend sur 11 fuseaux horaires — quand il est midi à Moscou, il est déjà 23h à la pointe est du pays."},
  {id:'w6',cat:'world',text:"Le drapeau du Népal est le seul au monde qui n'est ni carré ni rectangulaire — c'est la superposition de deux triangles."},
  {id:'w7',cat:'world',text:"Il y a statistiquement plus de flamants roses en plastique que de vrais flamants roses sur la planète."},
  {id:'w8',cat:'world',text:"La surface de la Russie est plus vaste que celle de la planète naine Pluton — 17 millions de km² contre 16,6 millions pour Pluton."},
  {id:'w9',cat:'world',text:"L'Islande est l'un des rares endroits au monde où il n'existe absolument aucun moustique — le climat et les conditions géologiques ne permettent pas leur développement."},
  {id:'w10',cat:'world',text:"Au Japon, l'île d'Okunoshima est entièrement peuplée de lapins sauvages et amicaux — d'anciens lapins de laboratoire abandonnés à la fin de la Seconde Guerre mondiale."},
  {id:'l1',cat:'language',text:"Le mot « robot » vient du tchèque « robota » qui signifie « travail forcé » — inventé par l'écrivain Karel Čapek dans une pièce de théâtre de 1920."},
  {id:'l2',cat:'language',text:"En japonais, il existe un mot unique pour la lumière qui filtre à travers les feuilles des arbres : « komorebi » — un concept sans équivalent direct en français."},
  {id:'l3',cat:'language',text:"Le mot « salaire » vient du latin « salarium » — la ration de sel donnée aux soldats romains, le sel étant alors aussi précieux que l'or."},
  {id:'l4',cat:'language',text:"Le mot « berserk » vient des guerriers vikings appelés berserkers — des combattants qui entraient en transe de rage lors des batailles."},
  {id:'l5',cat:'language',text:"L'anglais a emprunté plus de 30 % de son vocabulaire au français grâce à la conquête normande de 1066."},
  {id:'l6',cat:'language',text:"« OK » viendrait de « Oll Korrect », une faute d'orthographe volontaire devenue virale dans les journaux américains dès 1839."},
  {id:'l7',cat:'language',text:"« Oiseaux » est le plus long mot français dont aucune lettre individuelle ne se prononce telle quelle."},
  {id:'l8',cat:'language',text:"Le mot « emoji » vient du japonais « e » (image) et « moji » (lettre/caractère) — il n'a aucun lien avec le mot « émotion »."},
  {id:'l9',cat:'language',text:"Le mot « whisky » signifie littéralement « eau de vie » en gaélique irlandais — exactement comme « eau-de-vie » en français."},
  {id:'f1',cat:'food',text:"Le miel est l'un des rares aliments qui ne se périme jamais — des archéologues ont trouvé du miel vieux de 3 000 ans dans des tombes égyptiennes, encore parfaitement comestible."},
  {id:'f2',cat:'food',text:"Le chocolat était à l'origine une boisson amère et épicée bue froide par les Mayas et les Aztèques."},
  {id:'f3',cat:'food',text:"Les carottes n'étaient pas orange à l'origine — les Hollandais les ont sélectionnées en orange au XVIIe siècle, probablement en hommage à leur maison royale."},
  {id:'f4',cat:'food',text:"Le café est le deuxième produit le plus échangé au monde après le pétrole."},
  {id:'f5',cat:'food',text:"Les fraises ne sont pas des baies au sens botanique — mais les bananes, les avocats et les pastèques en sont."},
  {id:'f6',cat:'food',text:"Le piment fort ne brûle pas vraiment — la capsaïcine trompe les récepteurs de douleur thermique de ta langue."},
  {id:'f7',cat:'food',text:"Le Nutella a été inventé parce qu'il n'y avait plus assez de cacao après la guerre — Pietro Ferrero a ajouté des noisettes pour « allonger » la pâte."},
  {id:'f8',cat:'food',text:"Les Européens ont longtemps cru que les tomates étaient toxiques — leur acidité dissolvait le plomb des assiettes en étain."},
  {id:'f9',cat:'food',text:"Les biscuits fortune cookie ont été inventés au Japon, puis popularisés aux États-Unis par des immigrants japonais au début du XXe siècle."},
  {id:'f10',cat:'food',text:"Le chocolat blanc n'est techniquement pas du chocolat — il ne contient aucune particule solide de cacao."},
  {id:'sp01',cat:'sports',text:"Usain Bolt a couru le 100 mètres en 9,58 secondes en 2009 — une vitesse de pointe de 44,72 km/h."},
  {id:'sp02',cat:'sports',text:"Le marathon de 42,195 km tient sa distance d'un accident : aux JO de Londres en 1908, le départ fut décalé depuis Windsor pour que les enfants royaux voient la course depuis leurs fenêtres."},
  {id:'sp03',cat:'sports',text:"Michael Phelps a remporté plus de médailles d'or olympiques à lui seul que 161 pays dans toute leur histoire."},
  {id:'sp04',cat:'sports',text:"Le golf est le seul sport à avoir été pratiqué sur la Lune — en 1971, l'astronaute Alan Shepard a frappé deux balles sur le sol lunaire."},
  {id:'sp05',cat:'sports',text:"Le tir à la corde était une discipline officielle aux Jeux Olympiques entre 1900 et 1920."},
  {id:'sp06',cat:'sports',text:"Les balles de tennis sont devenues jaunes en 1972 pour être plus visibles sur les écrans de télévision en couleur."},
  {id:'sp07',cat:'sports',text:"Au tout début du basket-ball, on jouait avec des paniers à pêches fermés — il fallait arrêter le jeu pour récupérer le ballon avec une échelle après chaque panier."},
  {id:'sp08',cat:'sports',text:"Les médailles d'or olympiques actuelles sont composées à 92,5 % d'argent pur et seulement plaquées or."},
  {id:'sp09',cat:'sports',text:"Le record de vitesse d'un volant de badminton est de 493 km/h — frappé lors d'un smash en compétition."},
  {id:'spo10',cat:'sports',text:"Le premier marathon olympique en 1896 a été remporté par un berger grec, Spyridon Louis, qui s'est arrêté en chemin pour boire un verre de vin offert par des spectateurs."},

  // ─ CÉLÉBRITÉS ─
  {id:'cel1',cat:'celebrities',text:"Avant d'être acteur, Christopher Walken a travaillé comme dompteur de lions dans un cirque itinérant."},
  {id:'cel2',cat:'celebrities',text:"Steve Buscemi était pompier à New York avant de devenir acteur. Après les attentats du 11 septembre 2001, il a repris du service bénévolement plusieurs jours pour aider sa caserne d'origine."},
  {id:'cel3',cat:'celebrities',text:"Tom Hanks collectionne les machines à écrire anciennes et en possède plus de 250 provenant du monde entier."},
  {id:'cel4',cat:'celebrities',text:"Dolly Parton a un jour participé anonymement à un concours de sosies de Dolly Parton... et elle a perdu."},
  {id:'cel5',cat:'celebrities',text:"Margot Robbie a appris à retenir sa respiration pendant 5 minutes pour les besoins du film Suicide Squad."},
  {id:'cel6',cat:'celebrities',text:"Keanu Reeves a offert des montres Rolex personnalisées à toute l'équipe de cascadeurs de John Wick 4 en guise de remerciement."},
  {id:'cel7',cat:'celebrities',text:"Bill Murray n'a pas d'agent. Pour le contacter, les réalisateurs doivent laisser un message sur un répondeur secret qu'il ne consulte que rarement."},
  {id:'cel8',cat:'celebrities',text:"Barack Obama est un grand fan de bandes dessinées, particulièrement de Spider-Man et Conan le Barbare."},
  {id:'cel9',cat:'celebrities',text:"Nicolas Cage a un jour possédé une pieuvre de compagnie, affirmant que cela l'aidait à devenir un meilleur acteur en développant sa conscience."},
  {id:'cel10',cat:'celebrities',text:"Elvis Presley était ceinture noire de karaté, un art martial qu'il a commencé à pratiquer lors de son service militaire en Allemagne."},
  {id:'cel11',cat:'celebrities',text:"Johnny Depp voyage toujours avec son costume de Jack Sparrow pour pouvoir rendre visite à des enfants dans les hôpitaux à l'improviste."},
  {id:'cel12',cat:'celebrities',text:"Le vrai prénom d'Oprah Winfrey est Orpah, d'après un personnage biblique — mais tout le monde le prononçait de travers, et « Oprah » est resté."},
  {id:'cel13',cat:'celebrities',text:"Angelina Jolie possède une licence de pilote privé et son propre avion, un Cirrus SR22."},
  {id:'cel14',cat:'celebrities',text:"Jackie Chan détient le record du monde du plus grand nombre de cascades effectuées par un acteur vivant, selon le Guinness World Records."},
  {id:'cel15',cat:'celebrities',text:"Harrison Ford est un pilote d'hélicoptère de sauvetage chevronné et a personnellement secouru plusieurs randonneurs égarés dans des zones isolées."},
  {id:'cel16',cat:'celebrities',text:"Samuel L. Jackson a une clause dans tous ses contrats qui l'autorise à jouer au golf deux fois par semaine pendant les tournages."},
  {id:'cel17',cat:'celebrities',text:"Bryan Cranston travaillait comme révérend certifié pour marier des couples afin de gagner de l'argent avant le succès de Breaking Bad."},
  {id:'cel18',cat:'celebrities',text:"Ryan Gosling a lui-même construit la table de cuisine utilisée dans le film N'oublie jamais — le réalisateur lui a demandé ce qu'il saurait faire et il a répondu : menuiser."},
  {id:'cel19',cat:'celebrities',text:"Matthew McConaughey n'a pas utilisé de déodorant depuis plus de 30 ans. Ses partenaires à l'écran ont confirmé... sans se plaindre."},
  {id:'cel20',cat:'celebrities',text:"Keanu Reeves a secrètement donné une grande partie de son salaire de la trilogie Matrix à l'équipe technique du film."},
  // ─ FICTIONS ─
  {id:'fic1',cat:'fiction',text:"Sherlock Holmes ne porte jamais de casquette de chasseur dans les livres de Conan Doyle. C'est un illustrateur du magazine Strand qui l'a ajoutée, et elle est restée."},
  {id:'fic2',cat:'fiction',text:"Winnie l'Ourson a été inspiré par une vraie ourse nommée Winnipeg, amenée au Canada par un soldat et offerte au zoo de Londres — l'auteur A.A. Milne l'y emmenait régulièrement."},
  {id:'fic3',cat:'fiction',text:"La Kryptonite a été inventée en 1943 pour le feuilleton radio Superman car l'acteur voulait prendre des vacances. Il fallait une raison de le faire disparaître."},
  {id:'fic4',cat:'fiction',text:"J.K. Rowling a imaginé les noms des quatre maisons de Poudlard en les griffonnant sur un sac en papier dans un avion."},
  {id:'fic5',cat:'fiction',text:"Dans le livre original de Dr. Seuss, le Grinch n'est pas vert — il est blanc avec des taches roses. C'est l'adaptation télévisée de 1966 qui l'a rendu vert."},
  {id:'fic6',cat:'fiction',text:"Walt Disney voulait appeler sa souris « Mortimer », mais sa femme a trouvé le nom trop pompeux et a suggéré Mickey."},
  {id:'fic7',cat:'fiction',text:"Dans le livre original de Pinocchio, le protagoniste tue accidentellement le Criquet parlant dès les premières pages — loin du conte moral qu'on imagine."},
  {id:'fic8',cat:'fiction',text:"Ian Fleming a choisi le nom James Bond parce qu'il voulait le nom le plus simple et ennuyeux possible, qu'il a trouvé sur un guide d'ornithologie des Antilles."},
  {id:'fic9',cat:'fiction',text:"Dans la bande dessinée originale The Walking Dead, le mot « zombie » n'est presque jamais utilisé. Les personnages les appellent des « rôdeurs »."},
  {id:'fic10',cat:'fiction',text:"J.M. Barrie a cédé tous les droits d'auteur de Peter Pan à l'hôpital Great Ormond Street de Londres — une donation qui génère encore des revenus chaque année."},
  {id:'fic11',cat:'fiction',text:"Le nom de Gotham vient d'une bijouterie aperçue dans un annuaire par le créateur de Batman, Bob Kane — il cherchait un nom urbain et sombre."},
  {id:'fic12',cat:'fiction',text:"En yiddish, le mot « Shrek » signifie « peur » ou « terreur ». Les créateurs du film l'ignoraient complètement."},
  {id:'fic13',cat:'fiction',text:"Edgar Rice Burroughs a créé Tarzan sans jamais avoir mis les pieds en Afrique. Il n'a d'ailleurs jamais quitté l'Amérique du Nord."},
  {id:'fic14',cat:'fiction',text:"Agatha Christie finit par détester son personnage Hercule Poirot, le qualifiant d'égocentrique odieux — mais le public l'adorait trop pour qu'elle l'abandonne."},
  {id:'fic15',cat:'fiction',text:"George R.R. Martin écrit tous ses livres sur un ancien ordinateur sans internet tournant sous DOS, pour éviter toute distraction."},
  {id:'fic16',cat:'fiction',text:"L'auteure de Mary Poppins, P.L. Travers, a tellement détesté l'adaptation de Disney qu'elle a pleuré lors de la première et a longtemps refusé d'autres adaptations."},
  {id:'fic17',cat:'fiction',text:"Stephenie Meyer a eu l'idée de Twilight après un rêve très précis d'un vampire brillant dans une prairie — qu'elle a transcrit le lendemain matin."},
  {id:'fic18',cat:'fiction',text:"Bram Stoker n'est jamais allé en Transylvanie. Toute la documentation pour Dracula a été réalisée à la bibliothèque de Whitby en Angleterre."},
  // ─ JEUX VIDÉO ─
  {id:'gam1',cat:'gaming',text:"Le nom de Mario vient de Mario Segale, le propriétaire des entrepôts de Nintendo America, qui se pointait régulièrement pour réclamer son loyer en retard."},
  {id:'gam2',cat:'gaming',text:"Pac-Man a été inspiré par une pizza à laquelle il manquait une part — son créateur Toru Iwatani l'a lui-même confirmé en interview."},
  {id:'gam3',cat:'gaming',text:"Tetris est le premier jeu vidéo à avoir été joué dans l'espace : Aleksandr Serebrov y a joué sur Game Boy pendant sa mission en 1993."},
  {id:'gam4',cat:'gaming',text:"La princesse Zelda doit son nom à Zelda Fitzgerald, l'épouse de l'écrivain F. Scott Fitzgerald — une source d'inspiration confirmée par Shigeru Miyamoto."},
  {id:'gam5',cat:'gaming',text:"Avant de devenir un hérisson bleu, Sonic était passé par plusieurs designs incluant un tatou, un lapin et un chien dans les réunions de conception chez Sega."},
  {id:'gam6',cat:'gaming',text:"Final Fantasy doit son nom au fait que son créateur, Hironobu Sakaguchi, pensait que ce serait son dernier jeu avant de quitter l'industrie vidéoludique."},
  {id:'gam7',cat:'gaming',text:"La première version jouable de Minecraft a été développée en seulement six jours par Markus Persson, avant toute idée de la publier."},
  {id:'gam8',cat:'gaming',text:"Les bruits des Grognards dans Halo sont des enregistrements de l'équipe de développement de Bungie qui faisait des sons étranges avec sa bouche en studio."},
  {id:'gam9',cat:'gaming',text:"Le jeu Space Invaders devait à l'origine être plus rapide, mais les processeurs de l'époque ne pouvaient pas suivre — le ralentissement progressif est devenu un mécanisme de gameplay apprécié."},
  {id:'gam10',cat:'gaming',text:"World of Warcraft a servi de modèle à des épidémiologistes pour comprendre comment les maladies se propagent — une épidémie virtuelle de 2005 a été publiée dans The Lancet."},
  {id:'gam11',cat:'gaming',text:"Le mode multijoueur de GoldenEye sur Nintendo 64, devenu légendaire, a été ajouté en secret à la toute fin du développement sans l'accord de la direction."},
  {id:'gam12',cat:'gaming',text:"Les Sims a failli s'appeler « Tactical Domestic Simulator » — un nom que son créateur Will Wright a lui-même qualifié de catastrophique."},
  {id:'gam13',cat:'gaming',text:"Grand Theft Auto est né d'un bug dans un jeu de course de voitures : la police devenait subitement folle et percutait tout le monde. Les développeurs ont trouvé ça si amusant qu'ils en ont fait un jeu."},
  {id:'gam14',cat:'gaming',text:"Nintendo a été fondée en 1889 pour fabriquer des cartes à jouer — soit 70 ans avant que le mot « ordinateur » n'existe dans le grand public japonais."},
  {id:'gam15',cat:'gaming',text:"En japonais, « Pika » est le son d'une étincelle et « Chu » est le cri de la souris. Pikachu est donc littéralement une « souris-étincelle »."},
  {id:'gam16',cat:'gaming',text:"L'auteur polonais Andrzej Sapkowski a vendu les droits de The Witcher pour une somme forfaitaire dérisoire, ne croyant pas au potentiel des jeux vidéo. Il a depuis regretté publiquement cette décision."},
  {id:'gam17',cat:'gaming',text:"Lara Croft devait initialement s'appeler Laura Cruz, mais les développeurs de Core Design voulaient un nom plus britannique et ont trouvé « Croft » dans un annuaire téléphonique."},
  {id:'gam18',cat:'gaming',text:"La PlayStation était à l'origine un projet conjoint entre Nintendo et Sony pour créer une extension CD pour la Super Nintendo. La rupture du partenariat a poussé Sony à lancer sa propre console."},
  {id:'gam19',cat:'gaming',text:"Donkey Kong signifie littéralement « gorille stupide » : « Donkey » pour idiot et « Kong » pour gorille. Shigeru Miyamoto voulait que le nom soit mémorable en anglais."},
  {id:'gam20',cat:'gaming',text:"Le jeu Tetris a été créé en 1984 par un ingénieur soviétique, Alexeï Pajitnov, sur un ordinateur Elektronika 60."},
  // ─ CINÉMA ─
  {id:'cin1',cat:'cinema',text:"Le bruit des sabres laser de Star Wars a été créé par Ben Burtt en mélangeant le ronronnement d'un vieux projecteur de cinéma avec le son d'un câble métallique frappé."},
  {id:'cin2',cat:'cinema',text:"Pour la scène de la douche dans Psychose, Hitchcock a utilisé du sirop de chocolat pour simuler le sang — il rendait mieux que du vrai sang en noir et blanc."},
  {id:'cin3',cat:'cinema',text:"Le chat que tient Marlon Brando dans Le Parrain était un chat errant qui avait tout simplement décidé de s'installer sur le plateau. Coppola a laissé Brando le garder."},
  {id:'cin4',cat:'cinema',text:"Le cri du Vélociraptor dans Jurassic Park est en réalité un enregistrement de tortues en train de s'accoupler — trouvé par le designer sonore Gary Rydstrom."},
  {id:'cin5',cat:'cinema',text:"Dans Titanic, ce n'est pas Leonardo DiCaprio qui dessine Rose, mais le réalisateur James Cameron lui-même — qui se cache les deux mains dans le hors-champ."},
  {id:'cin6',cat:'cinema',text:"Christopher Lee, qui joue Saroumane dans Le Seigneur des Anneaux, était le seul membre de toute l'équipe à avoir personnellement rencontré J.R.R. Tolkien."},
  {id:'cin7',cat:'cinema',text:"Sylvester Stallone était tellement fauché avant Rocky qu'il a vendu son chien pour 40 dollars. Une fois payé pour le film, il l'a racheté pour 15 000 dollars."},
  {id:'cin8',cat:'cinema',text:"Heath Ledger s'est enfermé seul dans une chambre d'hôtel pendant un mois entier pour préparer son rôle du Joker dans The Dark Knight."},
  {id:'cin9',cat:'cinema',text:"La machine à remonter le temps de Retour vers le futur devait être un réfrigérateur. L'idée a été abandonnée par peur que des enfants s'enferment dans des frigos pour imiter le film."},
  {id:'cin10',cat:'cinema',text:"Toy Story est le tout premier long-métrage entièrement réalisé en images de synthèse de l'histoire du cinéma, sorti en 1995 par Pixar."},
  {id:'cin11',cat:'cinema',text:"Pour le film Interstellar, Christopher Nolan a fait planter 500 hectares de maïs pour une scène — puis les a revendus avec profit après le tournage."},
  {id:'cin12',cat:'cinema',text:"Dans Alien, les acteurs ne savaient pas que la créature allait sortir du torse de John Hurt. Leurs réactions d'horreur à la caméra sont donc entièrement authentiques."},
  {id:'cin13',cat:'cinema',text:"Le requin mécanique de Jaws tombait si souvent en panne que l'équipe l'avait surnommé « Bruce ». Spielberg a finalement décidé de montrer l'animal le moins possible — ce qui a rendu le film bien plus effrayant."},
  {id:'cin14',cat:'cinema',text:"Le film que Kevin regarde dans Maman j'ai raté l'avion (Angels with Filthy Souls) n'existe pas. Il a été tourné spécialement pour le film."},
  {id:'cin15',cat:'cinema',text:"Le code vert qui défile dans Matrix est en réalité une suite de recettes de sushis numérisées par le designer Simon Whiteley à partir du livre de cuisine de sa femme."},
  {id:'cin16',cat:'cinema',text:"Tony Todd a réellement mis des abeilles vivantes dans sa bouche pour la scène finale de Candyman (1992). Il a été piqué plusieurs fois et touché un bonus pour chaque piqûre."},
  {id:'cin17',cat:'cinema',text:"Dans E.T., les bruits de pas de l'extraterrestre ont été créés par le designer sonore en écrasant de la gélatine avec ses mains dans un bac."},
  {id:'cin18',cat:'cinema',text:"La date de naissance de Truman dans The Truman Show est le 30 avril — exactement la même que celle de l'acteur Jim Carrey."},
  // ─ MUSIQUE ─
  {id:'mus1',cat:'music',text:"Brian May, guitariste de Queen, a fabriqué sa propre guitare surnommée la « Red Special » à partir d'une vieille cheminée victorienne — elle lui sert encore aujourd'hui."},
  {id:'mus2',cat:'music',text:"Aucun des quatre membres des Beatles ne savait lire ou écrire la musique de manière conventionnelle. Tout était transmis à l'oreille ou fredonné aux arrangeurs."},
  {id:'mus3',cat:'music',text:"Le titre Smells Like Teen Spirit vient d'une marque de déodorant pour adolescentes que portait l'ex-petite amie de Kurt Cobain — il a découvert la marque en voyant l'inscription sur un mur."},
  {id:'mus4',cat:'music',text:"Michael Jackson a breveté des chaussures spéciales dotées de crampons qui se connectaient au sol pour lui permettre de se pencher en avant à 45 degrés sans tomber."},
  {id:'mus5',cat:'music',text:"Eminem a écrit Lose Yourself en une seule session d'écriture, sur le plateau de tournage du film 8 Mile, entre deux prises."},
  {id:'mus6',cat:'music',text:"Les casques emblématiques de Daft Punk coûtaient plus de 65 000 euros chacun et contenaient des systèmes de climatisation intégrés pour éviter la surchauffe."},
  {id:'mus7',cat:'music',text:"Prince a joué de 27 instruments différents sur son premier album — enregistré alors qu'il n'avait que 19 ans."},
  {id:'mus8',cat:'music',text:"Keith Richards affirme avoir trouvé le riff de Satisfaction dans son sommeil. Il a eu le réflexe de l'enregistrer sur une cassette avant de se rendormir."},
  {id:'mus9',cat:'music',text:"David Bowie avait une pupille dilatée en permanence — non pas pour une raison génétique, mais à cause d'un coup de poing reçu lors d'une bagarre d'école, qui avait paralysé ses muscles oculaires."},
  {id:'mus10',cat:'music',text:"Ed Sheeran a dormi dans les couloirs du métro londonien pendant plusieurs mois avant de devenir célèbre, incapable de payer un loyer."},
  {id:'mus11',cat:'music',text:"L'album The Dark Side of the Moon de Pink Floyd est resté dans le classement Billboard 200 pendant 741 semaines consécutives — soit plus de 14 ans d'affilée."},
  {id:'mus12',cat:'music',text:"Adele nomme ses albums d'après l'âge qu'elle avait quand elle a commencé à les écrire : 19, 21, 25, et 30."},
  {id:'mus13',cat:'music',text:"Lady Gaga a écrit Just Dance en seulement 10 minutes — une chanson qui est devenue numéro 1 dans plus de 10 pays."},
  {id:'mus14',cat:'music',text:"I Will Always Love You est une reprise d'une chanson écrite par Dolly Parton en 1973. Whitney Houston en a fait un tube mondial, mais c'est Dolly Parton qui a touché tous les droits."},
  {id:'mus15',cat:'music',text:"Jay-Z n'écrit jamais ses paroles sur papier. Il compose tout dans sa tête, mémorise les couplets, puis entre en studio et les enregistre directement."},
  {id:'mus16',cat:'music',text:"Britney Spears n'était pas la première destinataire de ...Baby One More Time. Le groupe TLC avait refusé le titre, le trouvant trop puéril."},
  {id:'mus17',cat:'music',text:"Appetite for Destruction de Guns N' Roses est l'album de début le plus vendu de tous les temps aux États-Unis avec plus de 18 millions de copies."},
  {id:'mus18',cat:'music',text:"Elvis Presley n'a jamais écrit une seule des chansons qu'il a interprétées — toutes ses chansons sont des compositions d'autres artistes."},

  // ── SCIENCE (s14→s20) ─────────────────────────────────────────────────
  {id:'s14',cat:'science',text:"L'ADN humain contient environ 3 milliards de paires de bases. Si on le déroulait entièrement, il mesurerait environ 2 mètres de long."},
  {id:'s15',cat:'science',text:"Un neutron libre se désintègre en environ 14 minutes et 38 secondes, se transformant en proton, électron et antineutrino."},
  {id:'s16',cat:'science',text:"Les tardigrades sont les animaux les plus résistants de la Terre : ils survivent au vide spatial, aux radiations extrêmes et à des températures de -272°C."},
  {id:'s17',cat:'science',text:"Le cerveau humain génère environ 23 watts d'électricité quand il est éveillé — assez pour alimenter une petite ampoule LED."},
  {id:'s18',cat:'science',text:"Les pieuvres ont trois cœurs et un sang bleu, grâce à l'hémocyanine, une protéine qui contient du cuivre au lieu du fer."},
  {id:'s19',cat:'science',text:"Un gramme d'ADN peut théoriquement stocker jusqu'à 215 pétaoctets de données — l'équivalent de 215 millions de gigaoctets."},
  {id:'s20',cat:'science',text:"La glace chaude, ou glace XVI, est une forme de glace qui se forme à très haute pression et qui est moins dense que l'eau liquide ordinaire."},

  // ── MONDE (w11→w20) ────────────────────────────────────────────────────
  {id:'w11',cat:'world',text:"Le Liechtenstein et l'Ouzbékistan sont les deux seuls pays au monde doublement enclavés — entourés uniquement de pays eux-mêmes sans accès à la mer."},
  {id:'w12',cat:'world',text:"La France est le pays qui possède le plus de fuseaux horaires au monde — 12 — grâce à ses territoires d'outre-mer répartis sur tous les continents."},
  {id:'w13',cat:'world',text:"La Mongolie est le pays le moins densément peuplé du monde, avec seulement 2 habitants par kilomètre carré."},
  {id:'w14',cat:'world',text:"En Norvège, il existe une ville appelée Å — le nom de localité le plus court du monde, une seule lettre qui signifie 'rivière' en vieux norrois."},
  {id:'w15',cat:'world',text:"Le lac Baïkal en Russie contient environ 20 % de l'eau douce non glacée de la planète."},
  {id:'w16',cat:'world',text:"Le mont Chimborazo en Équateur est le point de la Terre le plus éloigné du centre de la planète, surpassant l'Everest grâce au renflement équatorial."},
  {id:'w17',cat:'world',text:"La ville la plus proche du vide spatial est pas Tokyo ou Mexico, mais Quito en Équateur, qui se trouve à une altitude de 2 850 mètres."},
  {id:'w18',cat:'world',text:"Le Sénégal est entièrement entouré par la Gambie, sauf sur son littoral atlantique — la Gambie s'étire comme une langue à l'intérieur du territoire sénégalais."},
  {id:'w19',cat:'world',text:"L'Antarctique est le désert le plus grand et le plus sec du monde. Sa précipitation annuelle moyenne est inférieure à 200 mm, moins que le Sahara."},
  {id:'w20',cat:'world',text:"Le point le plus bas de la surface terrestre est la mer Morte, à 430 mètres en dessous du niveau de la mer. Sa salinité est si élevée qu'on y flotte naturellement."},

  // ── ANIMAUX (a15→a20) ──────────────────────────────────────────────────
  {id:'a15',cat:'animals',text:"Les perroquets gris d'Afrique peuvent apprendre plus de 1 000 mots et comprendre des concepts comme la couleur, la forme et le nombre zéro."},
  {id:'a16',cat:'animals',text:"Le requin-baleine est le plus grand poisson du monde — il peut mesurer jusqu'à 12 mètres — mais se nourrit principalement de plancton."},
  {id:'a17',cat:'animals',text:"Les crocodiles ne peuvent pas tirer la langue. Leur langue est fixée à la mâchoire inférieure par un ligament sur toute sa longueur."},
  {id:'a18',cat:'animals',text:"Les homards ne meurent pas de vieillesse au sens biologique — ils continuent à grandir tout au long de leur vie et meurent généralement d'épuisement lors de la mue."},
  {id:'a19',cat:'animals',text:"Les dauphins dorment avec un seul hémisphère cérébral à la fois — l'autre reste éveillé pour respirer et surveiller les prédateurs."},
  {id:'a20',cat:'animals',text:"Les requins sont plus anciens que les arbres. Les premiers requins sont apparus il y a environ 450 millions d'années, alors que les arbres n'existent que depuis 350 millions d'années."},

  // ── CORPS HUMAIN (b11→b20) ────────────────────────────────────────────
  {id:'b11',cat:'body',text:"La surface totale de tes poumons, si on les dépliait, couvrirait environ 70 mètres carrés — la taille d'un petit appartement."},
  {id:'b12',cat:'body',text:"Les ongles poussent quatre fois plus vite que les ongles de pieds. La main dominante pousse légèrement plus vite que l'autre."},
  {id:'b13',cat:'body',text:"Le nez humain peut détecter plus d'un trillion d'odeurs différentes. C'est 10 000 fois plus que ce que l'on pensait il y a encore vingt ans."},
  {id:'b14',cat:'body',text:"Le corps humain contient assez de fer pour forger un clou de 7 cm. La quasi-totalité de ce fer se trouve dans l'hémoglobine du sang."},
  {id:'b15',cat:'body',text:"Ton squelette se renouvelle entièrement tous les 10 ans — à 30 ans, tu n'as plus un seul os de ta naissance."},
  {id:'b16',cat:'body',text:"Les empreintes digitales se forment dès la 17e semaine de grossesse. Elles sont déterminées par les pressions aléatoires exercées sur les doigts dans le ventre maternel."},
  {id:'b17',cat:'body',text:"Le corps humain produit environ 25 millions de nouvelles cellules chaque seconde — plus vite que tu ne peux les compter."},
  {id:'b18',cat:'body',text:"Les dents humaines sont aussi dures que les dents de requin. L'émail dentaire est le tissu le plus dur du corps humain, aussi résistant que certains minéraux."},
  {id:'b19',cat:'body',text:"Le cerveau humain contient environ 86 milliards de neurones, chacun pouvant former jusqu'à 10 000 connexions synaptiques avec d'autres neurones."},
  {id:'b20',cat:'body',text:"Les os humains sont, à volume égal, quatre fois plus résistants que le béton armé. Le fémur peut supporter une pression de 1 700 kg avant de céder."},

  // ── ARTS (ar14→ar20) ──────────────────────────────────────────────────
  {id:'ar14',cat:'arts',text:"Le tableau le plus cher jamais vendu aux enchères est 'Salvator Mundi' de Léonard de Vinci, adjugé à 450,3 millions de dollars en 2017 chez Christie's."},
  {id:'ar15',cat:'arts',text:"Le Cri d'Edvard Munch a été volé deux fois au même musée d'Oslo — en 1994 et en 2004 — avant d'être récupéré à chaque fois."},
  {id:'ar16',cat:'arts',text:"Beethoven a composé certaines de ses œuvres les plus célèbres, dont la 9e Symphonie, après être devenu totalement sourd."},
  {id:'ar17',cat:'arts',text:"Le musée du Louvre à Paris est le musée le plus visité au monde, avec environ 9 millions de visiteurs par an avant la pandémie."},
  {id:'ar18',cat:'arts',text:"Frida Kahlo a réalisé 55 autoportraits sur ses 143 tableaux. Elle expliquait peindre sa propre image parce qu'elle se connaissait mieux que quiconque."},
  {id:'ar19',cat:'arts',text:"Le bleu 'Klein International' a été breveté par Yves Klein en 1960. Cet artiste français a créé une couleur ultramarïne si intense qu'il l'a fait enregistrer à son nom."},
  {id:'ar20',cat:'arts',text:"La Chapelle Sixtine de Michel-Ange a été peinte en quatre ans, de 1508 à 1512. Contrairement à la légende, il ne peignait pas allongé mais debout sur des échafaudages."},

  // ── HISTOIRE (h13→h20) ────────────────────────────────────────────────
  {id:'h13',cat:'history',text:"Le pharaon Ramsès II a signé avec les Hittites le premier traité de paix écrit de l'Histoire, en 1259 avant J.-C."},
  {id:'h14',cat:'history',text:"La Grande Muraille de Chine n'est pas visible depuis l'espace à l'œil nu, contrairement à la légende. Cette idée reçue est réfutée par les astronautes eux-mêmes."},
  {id:'h15',cat:'history',text:"Jules César a été kidnappé par des pirates en 75 av. J.-C. Il a ri de leur rançon, exigé qu'ils la doublent, puis les a fait crucifier après sa libération."},
  {id:'h16',cat:'history',text:"Les Vikings n'avaient pas de cornes sur leur casque. Cette idée est née d'une reconstitution théâtrale du XIXe siècle et n'a aucune base archéologique."},
  {id:'h17',cat:'history',text:"Les Samourais japonais testaient la qualité de leurs katanas sur des condamnés à mort — une pratique appelée « tameshigiri »."},
  {id:'h18',cat:'history',text:"Le premier message envoyé par internet — ancêtre ARPANET — en 1969 était 'lo'. Le mot 'login' s'est interrompu après deux lettres à cause d'un crash système."},
  {id:'h19',cat:'history',text:"L'Empire romain avait un réseau routier de plus de 80 000 kilomètres, dont certaines routes sont encore utilisées aujourd'hui."},
  {id:'h20',cat:'history',text:"Pendant la Seconde Guerre mondiale, le MI5 britannique a entraîné des pigeons voyageurs pour transporter des messages secrets depuis la France occupée."},

  // ── ESPACE (sp11→sp20) ────────────────────────────────────────────────
  {id:'sp11',cat:'space',text:"Sur la lune de Jupiter, Europe, un océan liquide se cache sous une croûte de glace — les scientifiques pensent qu'il pourrait abriter une forme de vie."},
  {id:'sp12',cat:'space',text:"Le Soleil représente 99,86 % de toute la masse du système solaire."},
  {id:'sp13',cat:'space',text:"Le point le plus froid connu dans l'univers est la nébuleuse du Boomerang, à −272 °C — un degré de plus seulement que le zéro absolu."},
  {id:'sp14',cat:'space',text:"La Voie lactée et Andromède entreront en collision dans environ 4,5 milliards d'années pour former une galaxie géante surnommée « Milkomeda »."},
  {id:'sp15',cat:'space',text:"En 2019, pour la première fois, un trou noir a été photographié directement grâce au réseau de télescopes Event Horizon."},
  {id:'sp16',cat:'space',text:"Pluton possède un glacier en forme de cœur, nommé Tombaugh Regio, composé d'azote glacé."},
  {id:'sp17',cat:'space',text:"Un jour sur la Lune dure environ 29,5 jours terrestres — la même durée que son orbite autour de la Terre, ce qui explique qu'on voit toujours la même face."},
  {id:'sp18',cat:'space',text:"Jupiter a une tempête qui dure depuis au moins 350 ans : la Grande Tache Rouge, un anticyclone si grand qu'il pourrait contenir deux planètes Terre."},
  {id:'sp19',cat:'space',text:"Les anneaux de Saturne, bien qu'immenses, sont étonnamment fins : leur épaisseur est en moyenne de seulement 10 mètres."},
  {id:'sp20',cat:'space',text:"Le son ne peut pas voyager dans l'espace. L'espace interstellaire est si vide qu'il n'y a pas de molécules pour propager les ondes sonores."},

  // ── INVENTIONS (inv12→inv20) ───────────────────────────────────────────
  {id:'inv12',cat:'inventions',text:"Le stéthoscope a été inventé en 1816 par René Laennec qui, gêné de coller son oreille sur la poitrine d'une patiente, a roulé une feuille de papier en tube."},
  {id:'inv13',cat:'inventions',text:"La machine à laver automatique a été inventée en 1937 — avant cela, le lavage du linge prenait une journée entière de travail manuel."},
  {id:'inv14',cat:'inventions',text:"L'aspirine, synthétisée en 1897, est l'un des médicaments les plus vendus au monde. L'acide acétylsalicylique était connu des Égyptiens anciens sous forme d'écorce de saule."},
  {id:'inv15',cat:'inventions',text:"Le premier brevet pour un téléphone a été déposé par Alexander Graham Bell le 14 février 1876 — seulement deux heures avant son concurrent Elisha Gray."},
  {id:'inv16',cat:'inventions',text:"Le WWW et Internet ne sont pas la même chose. Le web a été inventé par Tim Berners-Lee en 1989 et fonctionne par-dessus Internet, créé dans les années 1960."},
  {id:'inv17',cat:'inventions',text:"Le Kevlar, cinq fois plus résistant que l'acier à poids égal, a été découvert en 1965 par Stephanie Kwolek, une chimiste de DuPont, en travaillant sur des fibres légères."},
  {id:'inv18',cat:'inventions',text:"Le GPS a été initialement développé par l'armée américaine pendant la Guerre froide et n'a été rendu accessible aux civils qu'en 2000."},
  {id:'inv19',cat:'inventions',text:"Le GPS est disponible gratuitement pour le monde entier, mais il est entretenu par l'armée américaine qui en supporte seule les coûts — estimés à 2 milliards de dollars par an."},
  {id:'inv20',cat:'inventions',text:"Les lunettes ont été inventées en Italie vers 1286, mais pendant trois siècles, les opticiens ont gardé secret le procédé de fabrication des verres pour protéger leur monopole."},

  // ── LANGAGE (l10→l20) ─────────────────────────────────────────────────
  {id:'l10',cat:'language',text:"Le mot 'set' en anglais a le plus grand nombre de définitions dans le dictionnaire Oxford — plus de 430 sens différents recensés."},
  {id:'l11',cat:'language',text:"Le japonais possède au moins quatre systèmes d'écriture différents utilisés simultanément : hiragana, katakana, kanji et rōmaji."},
  {id:'l12',cat:'language',text:"L'arabe s'écrit de droite à gauche, sauf les chiffres qui s'écrivent de gauche à droite. Les 'chiffres arabes' que nous utilisons viennent en réalité d'Inde."},
  {id:'l13',cat:'language',text:"Le mot « ketchup » vient du chinois « kê-tsiap », une sauce de poisson fermenté importée en Europe au 17ᵉ siècle."},
  {id:'l14',cat:'language',text:"La langue avec le plus grand nombre de locuteurs natifs est le mandarin, avec environ 920 millions de personnes. L'anglais est troisième, derrière l'espagnol."},
  {id:'l15',cat:'language',text:"Le sifflement est une vraie langue dans les villages montagnards des Canaries et de Turquie. La langue sifflée Silbo Gomero est inscrite au patrimoine UNESCO."},
  {id:'l16',cat:'language',text:"Le mot 'quiz' serait apparu à Dublin en 1791 lorsqu'un directeur de théâtre paria qu'il pourrait introduire un nouveau mot dans le langage courant en une nuit, en le faisant graffiter partout."},
  {id:'l17',cat:'language',text:"Il existe une langue — le pirahã en Amazonie — qui n'a pas de mots pour les couleurs, pas de nombres, et pas de temps grammatical passé ou futur."},
  {id:'l18',cat:'language',text:"Le français est la seule langue qui est parlée sur cinq continents comme langue officielle. Il est langue officielle dans 29 pays à travers le monde."},
  {id:'l19',cat:'language',text:"L'alphabet coréen (hangul) a été créé en 1443 par le roi Sejong le Grand pour que le peuple puisse lire et écrire facilement."},
  {id:'l20',cat:'language',text:"Le langage des signes n'est pas universel. Chaque pays a sa propre langue des signes — la LSF en France et l'ASL aux États-Unis sont très différentes l'une de l'autre."},

  // ── GASTRONOMIE (f11→f20) ─────────────────────────────────────────────
  {id:'f11',cat:'food',text:"Le miel est le seul aliment qui ne se périme jamais : du miel vieux de 3 000 ans retrouvé dans des tombes égyptiennes était encore parfaitement comestible."},
  {id:'f12',cat:'food',text:"Les pommes font partie de la famille des roses, tout comme les poires, cerises, abricots et amandes. La famille des Rosacées regroupe de nombreux fruits comestibles."},
  {id:'f13',cat:'food',text:"La vanille est l'orchidée la plus cultivée au monde. Chaque fleur doit être pollinisée à la main en dehors du Mexique, car seule une abeille locale peut le faire naturellement."},
  {id:'f14',cat:'food',text:"Le Nutella utilise environ 25 % de la production mondiale de noisettes. La marque Ferrero est le plus grand acheteur de noisettes sur la planète."},
  {id:'f15',cat:'food',text:"Le parmesan est si précieux en Italie que des banques acceptent des meules comme garantie de prêt — avec des voûtes climatisées pour les stocker."},
  {id:'f16',cat:'food',text:"Le fromage est l'aliment le plus volé dans le monde. Il représente environ 4 % du total des produits alimentaires dérobés à travers le globe chaque année."},
  {id:'f17',cat:'food',text:"Le wasabi servi dans la plupart des restaurants en dehors du Japon est en réalité du raifort coloré — le vrai wasabi coûte environ 250 € le kilo."},
  {id:'f18',cat:'food',text:"Le fruit le plus odorant du monde, le durian, est interdit dans les transports en commun et les hôtels en Asie du Sud-Est à cause de son odeur."},
  {id:'f19',cat:'food',text:"Les épices comme la cannelle, le poivre et la muscade étaient autrefois plus précieuses que l'or. Le commerce des épices a été le moteur principal de l'exploration mondiale au XVe siècle."},
  {id:'f20',cat:'food',text:"La pizza Margherita a été créée à Naples en 1889 en l'honneur de la reine Margherita de Savoie. Ses couleurs — rouge, blanc, vert — représentent le drapeau italien."},

  // ── SPORTS (sp11→sp20) — already using sp01 prefix ────────────────────
  {id:'sp011',cat:'sports',text:"Le marathon a été allongé de 385 yards (352 m) aux JO de Londres 1908 pour que la course se termine devant la loge royale."},
  {id:'sp012',cat:'sports',text:"Le tennis de table ou ping-pong est le sport le plus pratiqué au monde en nombre de licenciés, devant le badminton et le volleyball."},
  {id:'sp013',cat:'sports',text:"Le cricket est le deuxième sport le plus regardé au monde avec 2,5 milliards de fans, principalement en Inde, au Pakistan et en Australie."},
  {id:'sp014',cat:'sports',text:"Le Tour de France est la compétition sportive annuelle la plus regardée au monde, avec environ 3,5 milliards de téléspectateurs cumulés sur 3 semaines."},
  {id:'sp015',cat:'sports',text:"La balle de golf comporte entre 300 et 500 petites fossettes. Ces alvéoles réduisent la traînée aérodynamique et peuvent doubler la distance de vol de la balle."},
  {id:'sp016',cat:'sports',text:"Les jeux Olympiques modernes ont été relancés en 1896 à Athènes par Pierre de Coubertin. Seuls 14 pays y participaient — contre plus de 200 aujourd'hui."},
  {id:'sp017',cat:'sports',text:"Un match de cricket peut durer jusqu'à 5 jours. Les Tests matches, forme la plus longue du jeu, sont considérés comme le format le plus exigeant du sport."},
  {id:'sp018',cat:'sports',text:"Serena Williams est souvent citée comme la meilleure tenniswoman de l'histoire avec 23 titres en Grand Chelem en simple, un record de l'ère Open."},
  {id:'sp019',cat:'sports',text:"Le football est le seul sport pratiqué dans tous les pays du monde reconnus par les Nations Unies. La FIFA compte plus de membres que l'ONU elle-même."},
  {id:'sp020',cat:'sports',text:"La vitesse maximale d'un service au tennis est de 263,4 km/h, record établi par l'Australien Sam Groth en 2012. La balle ne met que 0,2 seconde pour traverser le court."},

  // ── FICTION (fic19→fic20)
  {id:'fic19',cat:'fiction',text:"Le personnage de Dracula, créé par Bram Stoker en 1897, s'inspire d'un vrai prince roumain du XVe siècle, Vlad III, surnommé l'Empaleur pour ses méthodes de torture."},
  {id:'fic20',cat:'fiction',text:"Le Hobbit de Tolkien a été écrit pour ses enfants. Tolkien avait griffonné sur une feuille blanche d'un devoir scolaire : 'Dans un trou dans la terre vivait un hobbit.'"},
  // ── CINÉMA (cin19→cin20)
  {id:'cin19',cat:'cinema',text:"Le film Blanche-Neige de Disney en 1937 est le premier long métrage d'animation de l'histoire du cinéma. Il a coûté 1,5 million de dollars — une somme folle à l'époque."},
  {id:'cin20',cat:'cinema',text:"Le tournage de Titanic a coûté plus cher que la construction du vrai Titanic, même en ajustant pour l'inflation."},
  // ── MUSIQUE (mus19→mus20)
  {id:'mus19',cat:'music',text:"Freddie Mercury avait une tessiture vocale de quatre octaves, l'une des plus grandes jamais enregistrées dans le rock."},
  {id:'mus20',cat:'music',text:"Le 'La' de référence, utilisé pour accorder les instruments, est fixé à 440 Hz depuis 1939. Avant cette norme internationale, chaque pays utilisait une fréquence différente."},
,
  // ── NOUVELLES CATÉGORIES ──
  {id:'myth1',cat:'mythology',text:"Dans la mythologie grecque, Athéna est née toute armée du crâne de Zeus après un violent mal de tête."},
  {id:'myth2',cat:'mythology',text:"Le marteau de Thor, Mjölnir, a un manche trop court parce qu'un moucheron a piqué le nain forgeron pendant sa fabrication."},
  {id:'myth3',cat:'mythology',text:"Anubis, le dieu égyptien à tête de chacal, pesait le cœur des morts sur une balance face à une plume de vérité."},
  {id:'myth4',cat:'mythology',text:"Dans la mythologie japonaise, le Soleil est une déesse — Amaterasu — qui s'est cachée dans une grotte, plongeant le monde dans les ténèbres."},
  {id:'myth5',cat:'mythology',text:"Le Minotaure, mi-homme mi-taureau, vivait au centre d'un labyrinthe construit par l'architecte Dédale en Crète."},
  {id:'myth6',cat:'mythology',text:"Loki, le dieu nordique de la ruse, s'est un jour transformé en jument et a donné naissance à Sleipnir, le cheval à huit pattes d'Odin."},
  {id:'myth7',cat:'mythology',text:"Prométhée a été enchaîné à un rocher pour avoir volé le feu aux dieux. Chaque jour, un aigle lui dévorait le foie, qui repoussait la nuit."},
  {id:'myth8',cat:'mythology',text:"Dans la mythologie hindoue, l'univers repose sur le dos de quatre éléphants, eux-mêmes debout sur une tortue géante."},
  {id:'myth9',cat:'mythology',text:"Méduse était si effrayante qu'un simple regard transformait quiconque en pierre. Persée a utilisé un bouclier miroir pour la vaincre."},
  {id:'myth10',cat:'mythology',text:"Dans la mythologie celtique, le Chaudron de Dagda pouvait nourrir une armée entière sans jamais se vider."},
  {id:'myth11',cat:'mythology',text:"Le Styx est le fleuve des Enfers grecs. S'y baigner rendait invincible — c'est ainsi qu'Achille a été trempé, sauf par le talon."},
  {id:'myth12',cat:'mythology',text:"Fenrir, le loup géant de la mythologie nordique, était si puissant que les dieux l'ont enchaîné avec un ruban magique fait de bruit de chat et de racines de montagne."},
  {id:'myth13',cat:'mythology',text:"Orphée jouait de la lyre si divinement que même les rochers et les arbres se déplaçaient pour l'écouter."},
  {id:'myth14',cat:'mythology',text:"Dans la mythologie aztèque, Quetzalcóatl, le serpent à plumes, a créé l'humanité en arrosant des os volés aux Enfers avec son propre sang."},
  {id:'myth15',cat:'mythology',text:"Les Valkyries nordiques survolaient les champs de bataille pour choisir les guerriers les plus braves et les emmener au Valhalla."},
  {id:'myth16',cat:'mythology',text:"Sisyphe a été condamné par Zeus à pousser éternellement un rocher en haut d'une montagne, pour le voir redescendre à chaque fois."},
  {id:'myth17',cat:'mythology',text:"Dans la mythologie chinoise, Pan Gu a créé le monde en brisant l'œuf cosmique avec une hache, séparant le ciel de la terre."},
  {id:'myth18',cat:'mythology',text:"Icare s'est envolé avec des ailes de cire fabriquées par son père Dédale, mais il s'est approché trop près du Soleil et a chuté dans la mer."},
  {id:'myth19',cat:'mythology',text:"Cerbère, le chien à trois têtes, gardait les portes des Enfers grecs. Héraclès l'a capturé à mains nues comme douzième travail."},
  {id:'myth20',cat:'mythology',text:"Dans la mythologie maorie, Māui a pêché l'île du Nord de la Nouvelle-Zélande avec un hameçon magique fait de la mâchoire de sa grand-mère."},
  {id:'psy1',cat:'psychology',text:"L'effet Dunning-Kruger montre que moins on est compétent dans un domaine, plus on surestime ses capacités."},
  {id:'psy2',cat:'psychology',text:"Le cerveau humain retient plus facilement environ 7 éléments à la fois — c'est pourquoi les numéros de téléphone sont découpés en petits groupes."},
  {id:'psy3',cat:'psychology',text:"L'expérience de Milgram en 1961 a montré que 65 % des participants étaient prêts à administrer des chocs électriques mortels sur ordre d'une autorité."},
  {id:'psy4',cat:'psychology',text:"Le biais de confirmation nous pousse à ne chercher et retenir que les informations qui confirment nos croyances préexistantes."},
  {id:'psy5',cat:'psychology',text:"La simple exposition répétée à quelque chose suffit à nous le faire aimer davantage — c'est l'effet de simple exposition."},
  {id:'psy6',cat:'psychology',text:"L'effet Barnum explique pourquoi les horoscopes semblent toujours justes : on accepte des descriptions vagues comme personnellement pertinentes."},
  {id:'psy7',cat:'psychology',text:"Un sourire forcé peut quand même améliorer ton humeur — le simple fait de contracter les muscles du sourire envoie un signal positif au cerveau."},
  {id:'psy8',cat:'psychology',text:"L'expérience de Stanford en 1971 a montré que de simples étudiants pouvaient devenir cruels en 6 jours quand on leur donnait le rôle de gardiens de prison."},
  {id:'psy9',cat:'psychology',text:"Le paradoxe du choix : plus on a d'options, plus il est difficile de décider et moins on est satisfait de son choix final."},
  {id:'psy10',cat:'psychology',text:"L'effet de halo nous fait juger quelqu'un de plus intelligent, gentil et compétent simplement parce qu'il est physiquement attirant."},
  {id:'psy11',cat:'psychology',text:"On retient mieux une information si on l'apprend juste avant de dormir — le sommeil consolide la mémoire."},
  {id:'psy12',cat:'psychology',text:"La peur de manquer quelque chose (FOMO) active les mêmes zones du cerveau que la douleur physique."},
  {id:'psy13',cat:'psychology',text:"L'effet Zeigarnik montre qu'on se souvient mieux des tâches inachevées que des tâches terminées — le cerveau déteste le non-résolu."},
  {id:'psy14',cat:'psychology',text:"Le simple fait de tenir un objet chaud (comme une tasse de café) nous rend plus chaleureux et généreux envers les autres."},
  {id:'psy15',cat:'psychology',text:"La synesthésie fait que certaines personnes « voient » les sons en couleurs ou « goûtent » les mots — environ 4 % de la population est concernée."},
  {id:'psy16',cat:'psychology',text:"L'effet Ikea : on accorde plus de valeur à un objet qu'on a assemblé soi-même, même s'il est de moindre qualité."},
  {id:'psy17',cat:'psychology',text:"Le phénomène du mot sur le bout de la langue touche en moyenne une fois par semaine chaque adulte — et augmente avec l'âge."},
  {id:'psy18',cat:'psychology',text:"Les gens surestiment systématiquement à quel point les autres les observent — c'est l'effet projecteur."},
  {id:'psy19',cat:'psychology',text:"Écouter de la musique libère de la dopamine dans le cerveau, exactement comme manger du chocolat ou tomber amoureux."},
  {id:'psy20',cat:'psychology',text:"L'ancrage cognitif fait que le premier chiffre qu'on voit influence toutes nos estimations suivantes, même s'il est totalement arbitraire."},
  {id:'ocean1',cat:'oceans',text:"Plus de 80 % des océans n'ont jamais été explorés — on connaît mieux la surface de Mars que le fond de nos mers."},
  {id:'ocean2',cat:'oceans',text:"La fosse des Mariannes descend à 10 994 mètres de profondeur — si on y plaçait l'Everest, son sommet serait encore sous l'eau de plus d'un kilomètre."},
  {id:'ocean3',cat:'oceans',text:"Les méduses existent depuis plus de 500 millions d'années — elles sont apparues avant les dinosaures et même avant les poissons."},
  {id:'ocean4',cat:'oceans',text:"Un calmar colossal peut atteindre 14 mètres de long et possède les plus grands yeux du règne animal, de la taille d'un ballon de basket."},
  {id:'ocean5',cat:'oceans',text:"La baleine bleue est l'animal le plus grand ayant jamais existé — son cœur a la taille d'une petite voiture."},
  {id:'ocean6',cat:'oceans',text:"Il y a plus de 3 millions d'épaves au fond des océans, dont la plupart n'ont jamais été découvertes."},
  {id:'ocean7',cat:'oceans',text:"Le corail, bien qu'il ressemble à une plante, est un animal — et les récifs coralliens abritent 25 % de toute la vie marine."},
  {id:'ocean8',cat:'oceans',text:"L'océan produit plus de 50 % de l'oxygène que nous respirons, principalement grâce au phytoplancton microscopique."},
  {id:'ocean9',cat:'oceans',text:"La pression au fond de la fosse des Mariannes est de 1 086 bars — l'équivalent de 50 avions empilés sur une personne."},
  {id:'ocean10',cat:'oceans',text:"Le Gulf Stream transporte plus d'eau que tous les fleuves du monde réunis — il réchauffe le climat de l'Europe occidentale."},
  {id:'ocean11',cat:'oceans',text:"Certains poissons des abysses produisent leur propre lumière par bioluminescence — 90 % des créatures des grands fonds sont luminescentes."},
  {id:'ocean12',cat:'oceans',text:"Le sel contenu dans les océans, s'il était extrait et étalé, couvrirait tous les continents d'une couche de 150 mètres d'épaisseur."},
  {id:'ocean13',cat:'oceans',text:"La grande barrière de corail australienne est si vaste qu'on peut la voir depuis l'espace — elle s'étend sur plus de 2 300 kilomètres."},
  {id:'ocean14',cat:'oceans',text:"Les hippocampes sont les seuls animaux dont c'est le mâle qui porte les bébés — il peut donner naissance à 2 000 petits à la fois."},
  {id:'ocean15',cat:'oceans',text:"Le poisson-pierre est l'animal marin le plus venimeux au monde — il se camoufle parfaitement sur les fonds rocheux."},
  {id:'ocean16',cat:'oceans',text:"Les courants sous-marins forment un « tapis roulant océanique » qui fait circuler l'eau autour du globe en environ 1 000 ans."},
  {id:'ocean17',cat:'oceans',text:"Le cœlacanthe, un poisson qu'on croyait éteint depuis 65 millions d'années, a été redécouvert vivant en 1938 au large de l'Afrique du Sud."},
  {id:'ocean18',cat:'oceans',text:"Les vagues de l'océan peuvent voyager des milliers de kilomètres sans perdre leur énergie — des houles nées en Antarctique atteignent l'Alaska."},
  {id:'ocean19',cat:'oceans',text:"Les tortues de mer reviennent pondre sur la plage exacte où elles sont nées, même après 30 ans passés en pleine mer — elles s'orientent grâce au champ magnétique terrestre."},
  {id:'ocean20',cat:'oceans',text:"Le point Nemo, dans le Pacifique sud, est l'endroit le plus éloigné de toute terre — les humains les plus proches sont les astronautes de l'ISS."},
  {id:'rec1',cat:'records',text:"Le record du monde de planche (gainage) est de 9 heures, 30 minutes et 1 seconde, détenu par Daniel Scali en 2021."},
  {id:'rec2',cat:'records',text:"L'homme le plus grand jamais mesuré, Robert Wadlow, faisait 2,72 mètres à sa mort en 1940 — il grandissait encore."},
  {id:'rec3',cat:'records',text:"Le Rubik's Cube peut être résolu en seulement 3,13 secondes — le record mondial actuel. Il existe 43 quintillions de combinaisons possibles."},
  {id:'rec4',cat:'records',text:"La plus longue partie de Monopoly a duré 70 jours consécutifs — et la plus longue dans une baignoire, 99 heures."},
  {id:'rec5',cat:'records',text:"L'animal le plus bruyant est le cachalot : ses clics peuvent atteindre 230 décibels, assez pour assourdir un humain."},
  {id:'rec6',cat:'records',text:"Le plus grand puzzle jamais assemblé comptait 551 232 pièces et mesurait 15 mètres de long."},
  {id:'rec7',cat:'records',text:"La température la plus élevée jamais enregistrée sur Terre est de 56,7°C, à Furnace Creek dans la Vallée de la Mort en 1913."},
  {id:'rec8',cat:'records',text:"Le plus grand nombre de hot-dogs mangés en 10 minutes est 76, un record établi par Joey Chestnut en 2021."},
  {id:'rec9',cat:'records',text:"Le plus vieil arbre connu, un pin Bristlecone en Californie, a plus de 5 000 ans — il était déjà vieux quand les pyramides ont été construites."},
  {id:'rec10',cat:'records',text:"Felix Baumgartner a sauté de 39 kilomètres d'altitude en 2012, atteignant Mach 1,25 en chute libre — le premier humain à briser le mur du son sans véhicule."},
  {id:'rec11',cat:'records',text:"Le plus long vol sans escale a duré 19 heures et 16 minutes, entre Singapour et New York, sur 15 349 km."},
  {id:'rec12',cat:'records',text:"La plus grande collection de canards en caoutchouc appartient à Charlotte Lee : plus de 9 000 canards."},
  {id:'rec13',cat:'records',text:"Le mot le plus long en français est « anticonstitutionnellement » avec 25 lettres — mais les chimistes font bien pire."},
  {id:'rec14',cat:'records',text:"Le record d'apnée statique est de 24 minutes et 37 secondes, détenu par Budimir Šobat — sans respirer sous l'eau."},
  {id:'rec15',cat:'records',text:"La plus petite grenouille du monde, découverte en Papouasie, mesure 7,7 mm — elle tient sur un ongle."},
  {id:'rec16',cat:'records',text:"Le plus grand rassemblement de personnes déguisées en Schtroumpfs a réuni 3 549 participants en Allemagne en 2019."},
  {id:'rec17',cat:'records',text:"Le record de dominos renversés en chaîne est de plus de 5 millions, mis en place par une équipe néerlandaise."},
  {id:'rec18',cat:'records',text:"L'éclair le plus long jamais enregistré mesurait 768 kilomètres, du Mississippi au Texas, en 2020."},
  {id:'rec19',cat:'records',text:"Le plus grand bonhomme de neige jamais construit faisait 37 mètres de haut, à Bethel dans le Maine en 2008."},
  {id:'rec20',cat:'records',text:"Le livre le plus volé dans les bibliothèques du monde est le Guinness World Records lui-même."},
  {id:'quote1',cat:'quotes',text:"« La folie, c'est de faire toujours la même chose et de s'attendre à un résultat différent. » — cette phrase souvent attribuée à Einstein n'a aucune source vérifiable."},
  {id:'quote2',cat:'quotes',text:"« L'imagination est plus importante que le savoir. » — Albert Einstein. Il estimait que le savoir se limite au connu, tandis que l'imagination embrasse l'univers entier."},
  {id:'quote3',cat:'quotes',text:"Winston Churchill dormait chaque après-midi et travaillait souvent en pyjama. Sa devise : « Vous avez des ennemis ? Bien. Cela veut dire que vous avez défendu quelque chose. »"},
  {id:'quote4',cat:'quotes',text:"« Je pense, donc je suis. » — René Descartes a résumé toute la base de la philosophie moderne en cinq mots en 1637."},
  {id:'quote5',cat:'quotes',text:"Nelson Mandela a déclaré : « Cela semble toujours impossible jusqu'à ce que ce soit fait » — il a passé 27 ans en prison avant de devenir président."},
  {id:'quote6',cat:'quotes',text:"Marie Curie a dit : « Dans la vie, rien n'est à craindre, tout est à comprendre. » Elle reste la seule personne à avoir reçu un Nobel dans deux sciences différentes."},
  {id:'quote7',cat:'quotes',text:"« Soyez le changement que vous voulez voir dans le monde. » — Gandhi n'a en réalité jamais dit cette phrase exacte, mais une version plus longue et nuancée."},
  {id:'quote8',cat:'quotes',text:"Oscar Wilde a dit au douanier américain : « Je n'ai rien à déclarer, sauf mon génie. » Il vivait de bons mots autant que de littérature."},
  {id:'quote9',cat:'quotes',text:"« La créativité, c'est l'intelligence qui s'amuse. » — souvent attribuée à Einstein, cette phrase n'apparaît dans aucun de ses écrits."},
  {id:'quote10',cat:'quotes',text:"Simone de Beauvoir a écrit : « On ne naît pas femme, on le devient. » — une phrase de 1949 qui a fondé le féminisme moderne."},
  {id:'quote11',cat:'quotes',text:"« Eurêka ! » — Archimède aurait crié ce mot en sortant nu de son bain après avoir découvert le principe de la poussée dans l'eau."},
  {id:'quote12',cat:'quotes',text:"Mark Twain a dit : « Les deux jours les plus importants de ta vie sont le jour où tu es né et le jour où tu comprends pourquoi. »"},
  {id:'quote13',cat:'quotes',text:"Steve Jobs a lancé sa carrière dans un garage et conclu un célèbre discours à Stanford par : « Soyez insatiables, soyez fous. »"},
  {id:'quote14',cat:'quotes',text:"Voltaire écrivait debout et buvait jusqu'à 40 tasses de café par jour. Il a dit : « J'ai décidé d'être heureux parce que c'est bon pour la santé. »"},
  {id:'quote15',cat:'quotes',text:"Coco Chanel a révolutionné la mode et déclaré : « La mode se démode, le style jamais. » Elle a libéré les femmes du corset."},
  {id:'quote16',cat:'quotes',text:"Bruce Lee a dit : « Sois comme l'eau, mon ami. » Sa philosophie mêlait arts martiaux et sagesse taoïste."},
  {id:'quote17',cat:'quotes',text:"Frida Kahlo peignait depuis son lit d'hôpital et a dit : « Des pieds, pourquoi en aurais-je besoin, si j'ai des ailes pour voler ? »"},
  {id:'quote18',cat:'quotes',text:"Léonard de Vinci écrivait de droite à gauche en miroir. Il a noté : « La simplicité est la sophistication suprême. »"},
  {id:'quote19',cat:'quotes',text:"Muhammad Ali s'est proclamé « le plus grand » avant même de l'être. Sa devise : « Celui qui n'est pas assez courageux pour prendre des risques n'accomplira rien. »"},
  {id:'quote20',cat:'quotes',text:"Marie-Antoinette n'a probablement jamais dit « Qu'ils mangent de la brioche » — cette phrase circulait déjà des décennies avant elle."},
  {id:'law1',cat:'laws',text:"En Suisse, il est interdit de tirer la chasse d'eau après 22 heures dans un immeuble — pour préserver le repos des voisins."},
  {id:'law2',cat:'laws',text:"À Singapour, la vente de chewing-gum est interdite depuis 1992 — sauf prescription médicale d'un médecin ou dentiste."},
  {id:'law3',cat:'laws',text:"En France, il est techniquement illégal de nommer un cochon « Napoléon » — une loi jamais officiellement abrogée."},
  {id:'law4',cat:'laws',text:"En Thaïlande, marcher sur un billet de banque est un crime — il porte le portrait du roi, et l'insulter peut mener en prison."},
  {id:'law5',cat:'laws',text:"En Italie, un homme a été condamné à une amende pour avoir porté des tongs au volant — considéré comme conduite dangereuse."},
  {id:'law6',cat:'laws',text:"Au Japon, il est illégal d'être en surpoids excessif : la « loi Metabo » impose des contrôles de tour de taille aux entreprises."},
  {id:'law7',cat:'laws',text:"En Australie, il est interdit de déranger un pigeon voyageur — une loi datant de la Seconde Guerre mondiale, toujours en vigueur."},
  {id:'law8',cat:'laws',text:"En Allemagne, tomber en panne d'essence sur l'autoroute est une infraction — c'est considéré comme un arrêt volontaire évitable."},
  {id:'law9',cat:'laws',text:"En Angleterre, il est techniquement interdit de mourir au Parlement — car il faudrait organiser des funérailles d'État."},
  {id:'law10',cat:'laws',text:"Au Canada, la loi interdit de payer un achat de plus de 25 dollars entièrement en pièces de 1 cent — pour protéger les commerçants."},
  {id:'law11',cat:'laws',text:"En Grèce, porter des talons aiguilles sur des sites archéologiques est interdit — pour protéger les sols anciens."},
  {id:'law12',cat:'laws',text:"En Écosse, si quelqu'un frappe à ta porte pour utiliser les toilettes, tu es légalement obligé de le laisser entrer."},
  {id:'law13',cat:'laws',text:"À Venise, il est interdit de nourrir les pigeons sur la place Saint-Marc — sous peine d'une amende pouvant atteindre 700 euros."},
  {id:'law14',cat:'laws',text:"En Suède, il est illégal de repeindre sa maison sans autorisation du gouvernement — même la couleur doit être approuvée."},
  {id:'law15',cat:'laws',text:"Au Portugal, il est interdit d'uriner dans la mer — une loi rarement appliquée mais techniquement en vigueur."},
  {id:'law16',cat:'laws',text:"En Finlande, toute amende de circulation est proportionnelle au revenu — un millionnaire finlandais a reçu une amende de 100 000 € pour excès de vitesse."},
  {id:'law17',cat:'laws',text:"En Alabama, il est illégal de porter une fausse moustache à l'église si elle provoque des rires — une loi toujours en vigueur."},
  {id:'law18',cat:'laws',text:"Au Bhoutan, la vente de tabac est totalement interdite depuis 2004 — c'est le premier pays au monde à l'avoir fait."},
  {id:'law19',cat:'laws',text:"En Turquie, un homme de 65 ans ou plus peut légalement refuser de faire la queue — le respect des aînés est inscrit dans la loi."},
  {id:'law20',cat:'laws',text:"En Nouvelle-Zélande, tout citoyen a le droit de refuser le survol de sa propriété par un drone — une loi sur la vie privée très stricte."},
  {id:'tale1',cat:'tales',text:"Le Petit Chaperon rouge a été publié par Perrault en 1697 — dans la version originale, le loup mange la grand-mère ET l'enfant, sans sauvetage."},
  {id:'tale2',cat:'tales',text:"La légende du Yéti vient des Sherpas du Népal. En 2017, des analyses ADN de « preuves » se sont révélées être des poils d'ours brun de l'Himalaya."},
  {id:'tale3',cat:'tales',text:"Barbe-Bleue, le conte de Perrault, serait inspiré de Gilles de Rais, compagnon de Jeanne d'Arc devenu tueur en série au 15ᵉ siècle."},
  {id:'tale4',cat:'tales',text:"Le Kraken, monstre marin scandinave, était probablement inspiré par des observations de calmars géants — qui existent réellement."},
  {id:'tale5',cat:'tales',text:"Cendrillon existe dans plus de 500 versions à travers le monde. La plus ancienne, Rhodopis, est un conte égyptien du 1ᵉʳ siècle av. J.-C."},
  {id:'tale6',cat:'tales',text:"Le monstre du Loch Ness a été « vu » pour la première fois en l'an 565 par un moine irlandais, Saint Columba."},
  {id:'tale7',cat:'tales',text:"La Belle au bois dormant dort 100 ans dans le conte de Perrault — mais 500 ans dans la version de Basile, écrite en 1634 en Italie."},
  {id:'tale8',cat:'tales',text:"Les frères Grimm ont recueilli leurs contes auprès de sources orales allemandes — mais ils les ont considérablement réécrits et assombris."},
  {id:'tale9',cat:'tales',text:"La légende du Golem de Prague raconte qu'un rabbin du 16ᵉ siècle a créé un être d'argile vivant pour protéger le ghetto juif."},
  {id:'tale10',cat:'tales',text:"Dans la version originale de La Petite Sirène d'Andersen, elle ne finit pas avec le prince — elle se transforme en écume de mer."},
  {id:'tale11',cat:'tales',text:"Les dragons apparaissent dans les mythes de presque toutes les civilisations — d'Europe à la Chine en passant par les Amériques."},
  {id:'tale12',cat:'tales',text:"Robin des Bois est mentionné pour la première fois en 1377 dans un poème anglais — son existence historique n'a jamais été prouvée."},
  {id:'tale13',cat:'tales',text:"Le Chupacabra, créature légendaire d'Amérique latine, a été « inventé » en 1995 à Porto Rico — les analyses ont révélé des coyotes malades."},
  {id:'tale14',cat:'tales',text:"Pinocchio, dans le roman original de Collodi en 1883, est pendu et meurt à la fin — la version joyeuse a été ajoutée après les plaintes des lecteurs."},
  {id:'tale15',cat:'tales',text:"La Dame Blanche est une légende présente dans presque tous les pays d'Europe — un fantôme féminin lié à un château ou une route."},
  {id:'tale16',cat:'tales',text:"Le conte d'Hansel et Gretel serait né pendant la Grande Famine de 1315 en Europe, quand l'abandon d'enfants était une réalité."},
  {id:'tale17',cat:'tales',text:"Les loups-garous apparaissent dans les textes européens depuis l'Antiquité. Le plus ancien témoignage écrit date de Pétrone, au 1ᵉʳ siècle."},
  {id:'tale18',cat:'tales',text:"Le Roi Arthur et Excalibur apparaissent pour la première fois dans des textes gallois du 9ᵉ siècle — Camelot n'a jamais été localisé."},
  {id:'tale19',cat:'tales',text:"La légende japonaise de Kintarō raconte l'histoire d'un enfant si fort qu'il luttait avec des ours dans la forêt dès l'âge de 5 ans."},
  {id:'tale20',cat:'tales',text:"Le triangle des Bermudes a été popularisé dans les années 1960 — les statistiques montrent qu'il n'y a pas plus d'accidents là qu'ailleurs."},
  {id:'dino1',cat:'dinosaurs',text:"Le T-Rex avait la morsure la plus puissante de tous les animaux terrestres — environ 6 tonnes de pression, assez pour broyer une voiture."},
  {id:'dino2',cat:'dinosaurs',text:"Les dinosaures ont régné sur Terre pendant 165 millions d'années. L'humanité n'existe que depuis 300 000 ans."},
  {id:'dino3',cat:'dinosaurs',text:"Le Vélociraptor réel était de la taille d'un dindon et probablement couvert de plumes — bien loin de la version de Jurassic Park."},
  {id:'dino4',cat:'dinosaurs',text:"L'astéroïde qui a causé l'extinction des dinosaures a frappé le Yucatán il y a 66 millions d'années, créant un cratère de 180 km de diamètre."},
  {id:'dino5',cat:'dinosaurs',text:"Le Brachiosaure pesait environ 80 tonnes et mesurait 25 mètres — il devait manger 400 kg de plantes par jour pour survivre."},
  {id:'dino6',cat:'dinosaurs',text:"Les oiseaux sont les descendants directs des dinosaures théropodes — un moineau est techniquement un dinosaure vivant."},
  {id:'dino7',cat:'dinosaurs',text:"Le Stégosaure avait un cerveau de la taille d'une noix malgré un corps de 9 mètres — l'un des plus petits rapports cerveau/corps connus."},
  {id:'dino8',cat:'dinosaurs',text:"Le Spinosaure est le seul dinosaure connu qui vivait en milieu semi-aquatique — plus grand que le T-Rex, il pêchait comme un héron géant."},
  {id:'dino9',cat:'dinosaurs',text:"Les bras du T-Rex, bien que ridiculement courts, pouvaient soulever environ 200 kg chacun — ils n'étaient pas inutiles."},
  {id:'dino10',cat:'dinosaurs',text:"Le Parasaurolophus utilisait sa crête creuse comme un instrument de musique pour communiquer avec son troupeau à des kilomètres."},
  {id:'dino11',cat:'dinosaurs',text:"Le premier fossile de dinosaure scientifiquement décrit était un Megalosaurus, en 1824 en Angleterre, par William Buckland."},
  {id:'dino12',cat:'dinosaurs',text:"Le Quetzalcoatlus, un ptérosaure (pas un dinosaure), avait une envergure de 12 mètres — la taille d'un petit avion."},
  {id:'dino13',cat:'dinosaurs',text:"Certains dinosaures herbivores avalaient des pierres (gastrolithes) pour aider à broyer la nourriture dans leur estomac."},
  {id:'dino14',cat:'dinosaurs',text:"Le mot « dinosaure » signifie « lézard terrible » en grec — il a été inventé par Richard Owen en 1842."},
  {id:'dino15',cat:'dinosaurs',text:"L'Ankylosaurus avait une queue terminée par une massue osseuse capable de briser les os d'un T-Rex."},
  {id:'dino16',cat:'dinosaurs',text:"Le plus petit dinosaure connu, le Microraptor, mesurait 40 cm et avait quatre ailes — il planait entre les arbres comme un écureuil volant."},
  {id:'dino17',cat:'dinosaurs',text:"Les Tricératops vivaient en troupeaux et leurs cornes servaient autant au combat entre mâles qu'à la défense contre les prédateurs."},
  {id:'dino18',cat:'dinosaurs',text:"En Argentine, on a découvert le plus grand dinosaure connu : le Patagotitan, estimé à 70 tonnes et 37 mètres de long."},
  {id:'dino19',cat:'dinosaurs',text:"Les dinosaures pondaient des œufs. Le plus gros œuf de dinosaure jamais trouvé mesure 60 cm — attribué à un titanosaure."},
  {id:'dino20',cat:'dinosaurs',text:"Il n'y a jamais eu de dinosaures en Antarctique... si ? En fait, des fossiles y ont été trouvés — le continent était autrefois tempéré."},

  // ══════════════════════════════════════════════════════════════════════
  //  BATCH 3 — 10 nouveaux faits par catégorie (21 → 30)
  // ══════════════════════════════════════════════════════════════════════

  // ── SCIENCE (s21→s30) ──
  {id:'s21',cat:'science',text:"Les plantes « entendent » l'eau : leurs racines poussent vers le son d'un tuyau qui coule, même sans contact avec l'humidité."},
  {id:'s22',cat:'science',text:"La température la plus basse jamais créée en laboratoire est 38 picoKelvins — plus froide que le vide interstellaire."},
  {id:'s23',cat:'science',text:"Un seul éclair contient assez d'énergie pour griller 100 000 tranches de pain — mais elle se libère trop vite pour être captée."},
  {id:'s24',cat:'science',text:"Les cristaux de temps, prédits en 2012 et créés en 2017, oscillent sans jamais consommer d'énergie — un nouvel état de la matière."},
  {id:'s25',cat:'science',text:"La gravité fait passer le temps plus lentement : une horloge au rez-de-chaussée retarde très légèrement par rapport à une horloge au dernier étage."},
  {id:'s26',cat:'science',text:"Les flammes dans l'espace sont sphériques et bleues, car sans gravité il n'y a pas de convection pour étirer la flamme vers le haut."},
  {id:'s27',cat:'science',text:"Le verre n'est pas un liquide au ralenti — c'est un solide amorphe. Les vitraux anciens sont plus épais en bas à cause des techniques de fabrication."},
  {id:'s28',cat:'science',text:"Un photon émis au cœur du Soleil met entre 10 000 et 170 000 ans à atteindre sa surface, en rebondissant sans cesse sur les atomes."},
  {id:'s29',cat:'science',text:"Les tornades de feu existent : quand un incendie crée assez de chaleur, il peut engendrer un tourbillon de flammes pouvant dépasser 1 000 °C."},
  {id:'s30',cat:'science',text:"Le son le plus fort jamais enregistré est l'éruption du Krakatoa en 1883 — audible à 5 000 km, il a fait le tour du globe quatre fois."},

  // ── POSITIVE (p21→p30) ──
  {id:'p21',cat:'positive',text:"Le lynx ibérique, qui comptait 94 individus en 2002, dépasse aujourd'hui les 2 000 grâce aux programmes de réintroduction en Espagne et au Portugal."},
  {id:'p22',cat:'positive',text:"Depuis 2000, la scolarisation primaire est passée de 60 % à 90 % en Afrique subsaharienne — des dizaines de millions d'enfants de plus à l'école."},
  {id:'p23',cat:'positive',text:"Le Costa Rica produit plus de 99 % de son électricité à partir de sources renouvelables depuis plusieurs années consécutives."},
  {id:'p24',cat:'positive',text:"Le nombre de morts par catastrophes naturelles a diminué de 90 % en un siècle, grâce aux systèmes d'alerte et aux constructions parasismiques."},
  {id:'p25',cat:'positive',text:"L'Inde a planté 220 millions d'arbres en une seule journée en 2019 — un record mondial de reforestation."},
  {id:'p26',cat:'positive',text:"Le taux d'alphabétisation mondial est passé de 42 % en 1960 à 87 % aujourd'hui — le plus haut de l'histoire de l'humanité."},
  {id:'p27',cat:'positive',text:"Les populations de tigres sauvages augmentent pour la première fois en un siècle, passant de 3 200 en 2010 à environ 4 500 aujourd'hui."},
  {id:'p28',cat:'positive',text:"Le trou dans la couche d'ozone au-dessus de l'Antarctique a rétréci de 4 millions de km² depuis son pic dans les années 2000."},
  {id:'p29',cat:'positive',text:"Le Rwanda a interdit les sacs plastiques en 2008 et est devenu l'un des pays les plus propres d'Afrique en conséquence."},
  {id:'p30',cat:'positive',text:"La mortalité maternelle mondiale a été réduite de 34 % depuis 2000, avec des améliorations spectaculaires en Asie du Sud-Est."},

  // ── FUN (u21→u30) ──
  {id:'u21',cat:'fun',text:"Les wombats font des crottes cubiques — la seule espèce connue à produire des excréments de cette forme, probablement pour les empêcher de rouler."},
  {id:'u22',cat:'fun',text:"Un nuage d'orage pèse en moyenne 500 000 tonnes — l'équivalent de 100 000 éléphants flottant au-dessus de ta tête."},
  {id:'u23',cat:'fun',text:"Les flammes de bougies contiennent des millions de minuscules diamants d'environ 0,5 nanomètre qui se forment et disparaissent instantanément."},
  {id:'u24',cat:'fun',text:"Le miel ne coule pas en ligne droite : il forme des spirales et des boucles en tombant — un phénomène appelé « enroulement du miel »."},
  {id:'u25',cat:'fun',text:"La probabilité que deux personnes dans un groupe de 23 partagent la même date d'anniversaire est supérieure à 50 % — c'est le paradoxe des anniversaires."},
  {id:'u26',cat:'fun',text:"Les astronautes grandissent de 3 à 5 cm dans l'espace car leur colonne vertébrale s'étire sans la gravité — ils rétrécissent en revenant."},
  {id:'u27',cat:'fun',text:"Le nombre 111 111 111 multiplié par lui-même donne 12 345 678 987 654 321 — un palindrome parfait."},
  {id:'u28',cat:'fun',text:"Il pleut des diamants sur Jupiter et Saturne : la pression transforme le méthane atmosphérique en cristaux de carbone pur."},
  {id:'u29',cat:'fun',text:"Un pet humain voyage à environ 11 km/h et contient principalement de l'azote et du CO₂ — le sulfure d'hydrogène ne représente que 1 % mais cause toute l'odeur."},
  {id:'u30',cat:'fun',text:"Les poissons-clowns naissent tous mâles — le plus dominant du groupe change de sexe pour devenir femelle si la femelle disparaît."},

  // ── HISTORY (h21→h30) ──
  {id:'h21',cat:'history',text:"Gengis Khan a tué tellement de personnes que les forêts ont repoussé et le CO₂ mondial a diminué — un refroidissement climatique mesurable."},
  {id:'h22',cat:'history',text:"Pendant la Prohibition, le gouvernement américain empoisonnait volontairement l'alcool industriel — on estime que 10 000 personnes en sont mortes."},
  {id:'h23',cat:'history',text:"Les Incas n'avaient pas d'écriture, mais utilisaient des quipus — des cordes nouées — pour enregistrer des données numériques et narratives."},
  {id:'h24',cat:'history',text:"Le dernier duel officiel en France a eu lieu en 1967, entre le député Gaston Defferre et le député René Ribière — à l'épée."},
  {id:'h25',cat:'history',text:"L'Empire ottoman a duré 623 ans — plus longtemps que l'Empire romain d'Occident, du 14ᵉ au 20ᵉ siècle."},
  {id:'h26',cat:'history',text:"Le premier McDonald's a ouvert en 1940, mais la vraie révolution est venue de Ray Kroc en 1955 avec le système de franchise."},
  {id:'h27',cat:'history',text:"Les femmes suisses n'ont obtenu le droit de vote au niveau fédéral qu'en 1971 — l'un des derniers pays européens à le faire."},
  {id:'h28',cat:'history',text:"Alexandre le Grand n'a jamais perdu une seule bataille en 15 ans de campagne militaire — il est mort à 32 ans, probablement de fièvre."},
  {id:'h29',cat:'history',text:"Les Mayas avaient inventé le concept du zéro bien avant les Européens, dès le 4ᵉ siècle — indépendamment de l'Inde."},
  {id:'h30',cat:'history',text:"La Peste Noire a tué entre 30 % et 60 % de la population européenne au 14ᵉ siècle — environ 25 à 50 millions de personnes."},

  // ── SPACE (sp21→sp30) ──
  {id:'sp21',cat:'space',text:"La Station spatiale internationale se déplace à 28 000 km/h et fait le tour de la Terre en 90 minutes — ses occupants voient 16 levers de soleil par jour."},
  {id:'sp22',cat:'space',text:"Il y a plus d'étoiles dans l'univers observable que de grains de sable sur toutes les plages de la Terre — environ 200 milliards de milliards."},
  {id:'sp23',cat:'space',text:"La plus grande montagne connue du système solaire est Olympus Mons sur Mars — mais sur la lune Rhéa de Saturne, il existe un anneau rocheux en orbite."},
  {id:'sp24',cat:'space',text:"Titan, lune de Saturne, possède des lacs et des rivières — mais remplis de méthane liquide, pas d'eau."},
  {id:'sp25',cat:'space',text:"L'empreinte de pas de Buzz Aldrin sur la Lune est toujours intacte — sans vent ni pluie, elle pourrait rester visible pendant des millions d'années."},
  {id:'sp26',cat:'space',text:"Un an sur Neptune dure 165 années terrestres — la planète n'a complété qu'un seul tour du Soleil depuis sa découverte en 1846."},
  {id:'sp27',cat:'space',text:"La vitesse de la lumière est si « lente » à l'échelle cosmique qu'un signal envoyé vers l'étoile la plus proche mettrait 4,2 ans à arriver."},
  {id:'sp28',cat:'space',text:"Le télescope James Webb peut voir des galaxies formées 300 millions d'années après le Big Bang — soit il y a 13,5 milliards d'années."},
  {id:'sp29',cat:'space',text:"Vénus tourne dans le sens inverse de la plupart des planètes — sur Vénus, le Soleil se lève à l'ouest et se couche à l'est."},
  {id:'sp30',cat:'space',text:"Il existe un nuage d'alcool dans l'espace, Sagittarius B2, contenant assez d'éthanol pour remplir 400 000 milliards de milliards de pintes de bière."},

  // ── ANIMALS (a21→a30) ──
  {id:'a21',cat:'animals',text:"Les éléphants peuvent percevoir des vibrations sismiques à travers leurs pattes — ils « entendent » le sol à des kilomètres de distance."},
  {id:'a22',cat:'animals',text:"Le colibri est le seul oiseau capable de voler en arrière. Ses ailes battent jusqu'à 80 fois par seconde."},
  {id:'a23',cat:'animals',text:"Les rats rient quand on les chatouille — un son ultrasonique inaudible pour l'oreille humaine, découvert par le neuroscientifique Jaak Panksepp."},
  {id:'a24',cat:'animals',text:"L'axolotl peut régénérer un membre entier, y compris les os, les muscles et les nerfs — en quelques semaines seulement."},
  {id:'a25',cat:'animals',text:"Les chats ont un organe voméronasal qui leur permet de « goûter » les odeurs. C'est pourquoi ils font parfois cette grimace bouche ouverte appelée flehmen."},
  {id:'a26',cat:'animals',text:"Le poisson archer crache un jet d'eau d'une précision redoutable pour faire tomber les insectes posés sur les branches au-dessus de l'eau."},
  {id:'a27',cat:'animals',text:"Les hippopotames sécrètent une « sueur » rouge qui agit comme crème solaire et antibiotique naturel contre les bactéries."},
  {id:'a28',cat:'animals',text:"Les corbeaux de Nouvelle-Calédonie fabriquent et utilisent des outils — une capacité cognitive longtemps réservée aux primates."},
  {id:'a29',cat:'animals',text:"Le poulpe mimétique peut imiter l'apparence et le comportement de plus de 15 espèces différentes pour échapper aux prédateurs."},
  {id:'a30',cat:'animals',text:"Les manchots empereurs peuvent plonger à 500 mètres de profondeur et retenir leur souffle pendant 22 minutes."},

  // ── BODY (b21→b30) ──
  {id:'b21',cat:'body',text:"Le cerveau humain utilise 20 % de l'oxygène du corps mais ne représente que 2 % de la masse — c'est l'organe le plus gourmand en énergie."},
  {id:'b22',cat:'body',text:"Ton corps contient assez de carbone pour fabriquer environ 9 000 crayons à papier."},
  {id:'b23',cat:'body',text:"Les larmes de tristesse, de joie et d'oignon ont des compositions chimiques différentes — les larmes émotionnelles contiennent plus de protéines de stress."},
  {id:'b24',cat:'body',text:"L'intestin humain abrite environ 100 000 milliards de bactéries — dix fois plus que le nombre total de cellules humaines dans ton corps."},
  {id:'b25',cat:'body',text:"Le muscle le plus puissant du corps humain par rapport à sa taille est le masséter — le muscle de la mâchoire, capable d'exercer 70 kg de force."},
  {id:'b26',cat:'body',text:"Tes yeux traitent 36 000 informations par heure. En une vie, ils verront l'équivalent de 24 millions d'images."},
  {id:'b27',cat:'body',text:"Le corps humain émet une très légère lumière bioluminescente — 1 000 fois trop faible pour être perçue à l'œil nu."},
  {id:'b28',cat:'body',text:"Les neurones du cerveau communiquent à une vitesse pouvant atteindre 430 km/h — aussi vite qu'une voiture de Formule 1."},
  {id:'b29',cat:'body',text:"Le sang parcourt environ 19 000 km par jour dans ton corps — presque la moitié de la circonférence de la Terre."},
  {id:'b30',cat:'body',text:"Ta langue a une empreinte unique, tout comme tes doigts — aucune autre personne au monde n'a la même."},

  // ── ARTS (ar21→ar30) ──
  {id:'ar21',cat:'arts',text:"Van Gogh n'a vendu qu'un seul tableau de son vivant — La Vigne rouge — aujourd'hui ses œuvres valent des centaines de millions."},
  {id:'ar22',cat:'arts',text:"Le Penseur de Rodin ne représente pas un philosophe — c'est Dante contemplant les Enfers, pour la porte du musée des Arts décoratifs."},
  {id:'ar23',cat:'arts',text:"Le bleu outremer coûtait plus cher que l'or au Moyen Âge — fabriqué à partir de lapis-lazuli afghan, il était réservé à la Vierge Marie."},
  {id:'ar24',cat:'arts',text:"Banksy a installé un broyeur dans le cadre de sa toile Girl with Balloon qui s'est autodétruite en pleine vente aux enchères chez Sotheby's en 2018."},
  {id:'ar25',cat:'arts',text:"Claude Monet a peint plus de 250 tableaux de nymphéas dans son jardin de Giverny sur les 30 dernières années de sa vie."},
  {id:'ar26',cat:'arts',text:"Le Guernica de Picasso mesure 3,5 m × 7,8 m et a été peint en réponse au bombardement de la ville basque en 1937."},
  {id:'ar27',cat:'arts',text:"Le premier film de l'histoire, La Sortie de l'usine Lumière, ne dure que 46 secondes — tourné en 1895 à Lyon."},
  {id:'ar28',cat:'arts',text:"Michel-Ange considérait la sculpture comme supérieure à la peinture — la Chapelle Sixtine était pour lui une corvée imposée par le pape."},
  {id:'ar29',cat:'arts',text:"Le tableau La Nuit étoilée a été peint par Van Gogh depuis sa fenêtre à l'asile de Saint-Rémy-de-Provence en 1889."},
  {id:'ar30',cat:'arts',text:"Le street art était illégal partout il y a 30 ans — aujourd'hui, certaines œuvres sont protégées par les municipalités et valent des millions."},

  // ── INVENTIONS (inv21→inv30) ──
  {id:'inv21',cat:'inventions',text:"Le moteur à réaction a été inventé indépendamment par deux hommes qui ne se connaissaient pas — Frank Whittle en Angleterre et Hans von Ohain en Allemagne."},
  {id:'inv22',cat:'inventions',text:"Le code-barres a été inspiré par le code Morse : son inventeur, Norman Woodland, a tracé des points et tirets dans le sable d'une plage."},
  {id:'inv23',cat:'inventions',text:"Le premier ascenseur de sécurité a été présenté par Elisha Otis en 1854 — il s'est tenu dedans et a coupé le câble devant le public."},
  {id:'inv24',cat:'inventions',text:"Le pacemaker a été inventé par accident en 1956 quand Wilson Greatbatch a inséré la mauvaise résistance dans un circuit."},
  {id:'inv25',cat:'inventions',text:"Le plastique Lego est si précis que deux briques fabriquées à 60 ans d'intervalle s'emboîtent encore parfaitement."},
  {id:'inv26',cat:'inventions',text:"Le premier SMS de l'histoire, envoyé en 1992, disait simplement « Merry Christmas »."},
  {id:'inv27',cat:'inventions',text:"La fermeture éclair a mis 20 ans à être adoptée — inventée en 1893, elle n'est devenue courante qu'après la Première Guerre mondiale."},
  {id:'inv28',cat:'inventions',text:"Le Teflon a été découvert par accident en 1938 — le chimiste Roy Plunkett a trouvé un résidu blanc et glissant dans une bonbonne de gaz."},
  {id:'inv29',cat:'inventions',text:"La dynamite a été inventée par Alfred Nobel, qui a ensuite créé le prix Nobel pour compenser la destruction causée par son invention."},
  {id:'inv30',cat:'inventions',text:"Le premier appareil photo numérique, créé par Kodak en 1975, pesait 3,6 kg et prenait des images de 0,01 mégapixel."},

  // ── LANGUAGE (l21→l30) ──
  {id:'l21',cat:'language',text:"Le mot « pantalon » vient de Pantalone, un personnage de la commedia dell'arte italienne qui portait des hauts-de-chausses collants."},
  {id:'l22',cat:'language',text:"En finnois, le mot « kalsarikännit » désigne le fait de boire seul chez soi en sous-vêtements — un concept si courant qu'il a son propre emoji officiel."},
  {id:'l23',cat:'language',text:"Le mot « assassin » vient de l'arabe « hashshashin » — les membres d'une secte médiévale qui, selon la légende, consommaient du haschisch."},
  {id:'l24',cat:'language',text:"Il n'existe pas de mot pour « s'il vous plaît » en islandais — la politesse passe par d'autres constructions de phrase."},
  {id:'l25',cat:'language',text:"Le mot « muscle » vient du latin « musculus » qui signifie « petite souris » — les Romains trouvaient que les biceps en mouvement ressemblaient à une souris sous la peau."},
  {id:'l26',cat:'language',text:"L'inuktitut, langue inuite, possède plus de 50 mots pour décrire différents types de neige et de glace."},
  {id:'l27',cat:'language',text:"Le mot « cravate » vient de « croate » — les mercenaires croates du 17ᵉ siècle portaient des foulards noués au cou qui ont lancé la mode en France."},
  {id:'l28',cat:'language',text:"Le « lorem ipsum » utilisé en typographie est un texte latin de Cicéron, volontairement altéré et découpé depuis le 16ᵉ siècle."},
  {id:'l29',cat:'language',text:"Le basque (euskara) est la seule langue européenne qui n'a aucun parent connu — sa famille linguistique reste un mystère total."},
  {id:'l30',cat:'language',text:"Le mot « chandelier » vient du français « chandelle » — emprunté tel quel en anglais, il garde sa prononciation francisée."},

  // ── FOOD (f21→f30) ──
  {id:'f21',cat:'food',text:"Le safran est l'épice la plus chère du monde — il faut cueillir à la main 150 000 fleurs de crocus pour produire un seul kilogramme."},
  {id:'f22',cat:'food',text:"Les noix de cajou poussent à l'extérieur du fruit, sur une pomme de cajou — et elles sont toxiques à l'état cru."},
  {id:'f23',cat:'food',text:"Le ketchup était vendu comme médicament dans les années 1830 aux États-Unis — on lui prêtait des vertus contre la diarrhée."},
  {id:'f24',cat:'food',text:"Le croissant n'est pas français — il a été inventé à Vienne en Autriche pour célébrer la victoire contre les Ottomans en 1683."},
  {id:'f25',cat:'food',text:"Le Champagne a été perfectionné par Dom Pérignon, mais il n'a pas inventé les bulles — elles étaient considérées comme un défaut avant lui."},
  {id:'f26',cat:'food',text:"Les carottes violettes étaient la norme avant le 17ᵉ siècle — la carotte orange est une sélection génétique relativement récente."},
  {id:'f27',cat:'food',text:"Le cacao contient de la théobromine, un composé toxique pour les chiens et les chats mais inoffensif pour les humains."},
  {id:'f28',cat:'food',text:"La pomme de terre a été interdite en France jusqu'en 1772 — on la croyait responsable de la lèpre avant que Parmentier ne la réhabilite."},
  {id:'f29',cat:'food',text:"Le sel rose de l'Himalaya tire sa couleur du fer et de plus de 80 minéraux — mais il vient en réalité du Pakistan, pas du Népal."},
  {id:'f30',cat:'food',text:"Le popcorn éclate parce que chaque grain contient une goutte d'eau qui se transforme en vapeur à 180 °C, faisant exploser l'enveloppe."},

  // ── SPORTS (sp021→sp030) ──
  {id:'sp021',cat:'sports',text:"Pelé a marqué plus de 1 200 buts en carrière — un total que personne n'a jamais approché dans le football professionnel."},
  {id:'sp022',cat:'sports',text:"Le premier match de football féminin officiel a attiré 53 000 spectateurs en Angleterre en 1920 — la fédération l'a ensuite interdit pendant 50 ans."},
  {id:'sp023',cat:'sports',text:"Un terrain de football américain est recouvert de 40 millions de brins d'herbe synthétique — chacun mesurant environ 5 cm."},
  {id:'sp024',cat:'sports',text:"Le record de vitesse sur un vélo est de 280 km/h — établi par Denise Mueller-Korenek en 2018, dans l'aspiration d'un dragster."},
  {id:'sp025',cat:'sports',text:"Les sumotori mangent un ragoût spécial appelé chankonabe contenant 10 000 calories — mais ils ne prennent que deux repas par jour."},
  {id:'sp026',cat:'sports',text:"Le tennis a été inventé en France au 12ᵉ siècle sous le nom de « jeu de paume » — on frappait la balle avec la main."},
  {id:'sp027',cat:'sports',text:"Wilt Chamberlain a marqué 100 points en un seul match NBA en 1962 — un record qui tient toujours après plus de 60 ans."},
  {id:'sp028',cat:'sports',text:"La natation n'était pas enseignée aux marins jusqu'au 19ᵉ siècle — on croyait que ne pas savoir nager les décourageait de tomber à l'eau."},
  {id:'sp029',cat:'sports',text:"Les Jeux Olympiques anciens duraient cinq jours et les athlètes concouraient entièrement nus — le mot gymnase vient du grec « gymnos » (nu)."},
  {id:'sp030',cat:'sports',text:"Le saut en parachute a été inventé par André-Jacques Garnerin en 1797 — il a sauté d'un ballon à 900 mètres au-dessus de Paris."},

  // ── CELEBRITIES (cel21→cel30) ──
  {id:'cel21',cat:'celebrities',text:"Dwayne « The Rock » Johnson a été arrêté huit ou neuf fois avant l'âge de 17 ans pour bagarres et petits délits."},
  {id:'cel22',cat:'celebrities',text:"Natalie Portman a co-signé deux articles dans des revues scientifiques sur les neurosciences pendant ses études à Harvard."},
  {id:'cel23',cat:'celebrities',text:"Rowan Atkinson (Mr. Bean) a un master en génie électrique d'Oxford et a écrit sa thèse sur les systèmes de contrôle auto-adaptatifs."},
  {id:'cel24',cat:'celebrities',text:"Lady Gaga a appris le piano à l'âge de 4 ans et a été acceptée à la Juilliard School avant de rejoindre la Tisch School of the Arts de NYU."},
  {id:'cel25',cat:'celebrities',text:"Elon Musk a codé et vendu son premier jeu vidéo, Blastar, à l'âge de 12 ans pour 500 dollars."},
  {id:'cel26',cat:'celebrities',text:"Hedy Lamarr, star hollywoodienne des années 40, a co-inventé un système de saut de fréquence qui est à la base du Wi-Fi et du Bluetooth."},
  {id:'cel27',cat:'celebrities',text:"Arnold Schwarzenegger était déjà millionnaire grâce à l'immobilier avant même de devenir acteur à Hollywood."},
  {id:'cel28',cat:'celebrities',text:"Tim Cook (CEO d'Apple) se lève tous les jours à 3h45 du matin pour lire les e-mails des clients et faire du sport."},
  {id:'cel29',cat:'celebrities',text:"J.K. Rowling a été refusée par 12 éditeurs avant que Bloomsbury n'accepte Harry Potter — sur les conseils de la fille du directeur, âgée de 8 ans."},
  {id:'cel30',cat:'celebrities',text:"Shakira parle couramment six langues : espagnol, anglais, portugais, italien, français et arabe."},

  // ── FICTION (fic21→fic30) ──
  {id:'fic21',cat:'fiction',text:"Tolkien a inventé les langues elfiques en premier — l'univers de la Terre du Milieu a été créé pour leur donner un contexte."},
  {id:'fic22',cat:'fiction',text:"Le monstre de Frankenstein n'a pas de nom — « Frankenstein » est le nom du docteur qui le crée, pas de la créature."},
  {id:'fic23',cat:'fiction',text:"Stephen King a jeté le manuscrit de Carrie à la poubelle — c'est sa femme Tabitha qui l'a récupéré et l'a convaincu de le finir."},
  {id:'fic24',cat:'fiction',text:"Le Petit Prince d'Antoine de Saint-Exupéry est le livre le plus traduit au monde après la Bible — en plus de 500 langues et dialectes."},
  {id:'fic25',cat:'fiction',text:"Arthur Conan Doyle a tué Sherlock Holmes dans La Chute finale — mais la révolte des lecteurs l'a forcé à le ressusciter dix ans plus tard."},
  {id:'fic26',cat:'fiction',text:"L'Odyssée d'Homère, écrite il y a environ 2 800 ans, est considérée comme le premier roman d'aventure de l'histoire littéraire occidentale."},
  {id:'fic27',cat:'fiction',text:"Le jeu de plateau Cluedo a été inventé en 1943 par un musicien anglais, Anthony Pratt, pendant les black-outs de la Seconde Guerre mondiale."},
  {id:'fic28',cat:'fiction',text:"Dans la série originale des frères Grimm, Raiponce tombe enceinte dans sa tour — un détail supprimé des versions pour enfants."},
  {id:'fic29',cat:'fiction',text:"Le mot « utopie » a été inventé par Thomas More en 1516 — il vient du grec et signifie littéralement « lieu qui n'existe pas »."},
  {id:'fic30',cat:'fiction',text:"Don Quichotte de Cervantès, publié en 1605, est considéré comme le premier roman moderne — il se moque déjà des clichés de la chevalerie."},

  // ── GAMING (gam21→gam30) ──
  {id:'gam21',cat:'gaming',text:"Le jeu Dark Souls a popularisé le genre « die and retry » et le message « You Died » est devenu l'un des écrans les plus iconiques du jeu vidéo."},
  {id:'gam22',cat:'gaming',text:"Le premier easter egg de l'histoire du jeu vidéo est dans Adventure (Atari, 1979) — le développeur a caché son nom car Atari ne créditait pas les créateurs."},
  {id:'gam23',cat:'gaming',text:"La Game Boy originale a survécu à un bombardement lors de la guerre du Golfe — brûlée à l'extérieur, elle fonctionnait encore parfaitement."},
  {id:'gam24',cat:'gaming',text:"Le premier match d'e-sport a eu lieu à Stanford en 1972 — le prix du tournoi de Spacewar était un abonnement d'un an au magazine Rolling Stone."},
  {id:'gam25',cat:'gaming',text:"Animal Crossing se déroule en temps réel — les saisons, l'heure et les événements suivent le calendrier et l'horloge du joueur."},
  {id:'gam26',cat:'gaming',text:"Le Konami Code (↑↑↓↓←→←→BA) est apparu pour la première fois dans Gradius en 1986 — le programmeur l'avait créé pour se faciliter les tests."},
  {id:'gam27',cat:'gaming',text:"Le record du monde de Pac-Man est un score parfait de 3 333 360 points — il faut manger chaque point, fruit et fantôme sur 256 niveaux sans mourir."},
  {id:'gam28',cat:'gaming',text:"Red Dead Redemption 2 a coûté environ 500 millions de dollars à développer et a mobilisé plus de 2 000 personnes sur huit ans."},
  {id:'gam29',cat:'gaming',text:"Les Creepers de Minecraft sont nés d'un bug — Notch a accidentellement inversé les dimensions du modèle d'un cochon, obtenant une créature verticale étrange."},
  {id:'gam30',cat:'gaming',text:"Le jeu le plus joué au monde est actuellement Roblox, avec plus de 200 millions d'utilisateurs actifs mensuels, dont la majorité a moins de 16 ans."},

  // ── CINEMA (cin21→cin30) ──
  {id:'cin21',cat:'cinema',text:"Stanley Kubrick a utilisé uniquement de la lumière de bougie pour les scènes intérieures de Barry Lyndon — il a fait fabriquer un objectif spécial par Zeiss."},
  {id:'cin22',cat:'cinema',text:"Le mot « Rosebud » dans Citizen Kane fait référence au traîneau d'enfance de Kane — c'est l'un des plus célèbres spoilers de l'histoire du cinéma."},
  {id:'cin23',cat:'cinema',text:"Dans Fight Club, un gobelet Starbucks apparaît dans presque toutes les scènes — le réalisateur David Fincher l'a fait exprès comme commentaire sur le consumérisme."},
  {id:'cin24',cat:'cinema',text:"Viggo Mortensen a réellement dévié la lame lancée vers lui dans Le Seigneur des Anneaux — ce plan non prévu a été conservé au montage."},
  {id:'cin25',cat:'cinema',text:"Pixar a failli perdre Toy Story 2 quand quelqu'un a accidentellement lancé la commande de suppression du film entier — une employée en congé maternité en avait une copie chez elle."},
  {id:'cin26',cat:'cinema',text:"Le son du dinosaure dans Jurassic Park quand il barrit est un bébé éléphant ralenti, mélangé à un tigre et un alligator."},
  {id:'cin27',cat:'cinema',text:"Alfred Hitchcock avait tellement peur des œufs qu'il en a fait une véritable phobie — l'ovophobie — sans jamais comprendre pourquoi."},
  {id:'cin28',cat:'cinema',text:"Le personnage de Shrek était initialement doublé par Chris Farley, qui a enregistré 80 % du film avant de décéder — Mike Myers a repris le rôle."},
  {id:'cin29',cat:'cinema',text:"Le film Parasite de Bong Joon-ho est le premier film non anglophone à remporter l'Oscar du meilleur film, en 2020."},
  {id:'cin30',cat:'cinema',text:"L'explosion dans The Dark Knight où le Joker sort de l'hôpital a été filmée en une seule prise — l'hésitation de Heath Ledger n'était pas prévue."},

  // ── MUSIC (mus21→mus30) ──
  {id:'mus21',cat:'music',text:"Mozart avait un humour scatologique bien documenté — il a écrit un canon intitulé « Leck mich im Arsch » (Lèche-moi le derrière)."},
  {id:'mus22',cat:'music',text:"Le vinyle a fait un retour spectaculaire : en 2023, les ventes de disques vinyles ont dépassé celles des CD pour la première fois depuis 1987."},
  {id:'mus23',cat:'music',text:"La chanson Happy Birthday était sous copyright jusqu'en 2016 — Warner en tirait environ 2 millions de dollars par an de royalties."},
  {id:'mus24',cat:'music',text:"Le son du didgeridoo australien est produit par une vibration continue des lèvres — les joueurs utilisent la respiration circulaire pour ne jamais s'arrêter."},
  {id:'mus25',cat:'music',text:"Billie Eilish a enregistré son premier album à succès, When We All Fall Asleep, dans la chambre de son frère Finneas à Los Angeles."},
  {id:'mus26',cat:'music',text:"Metallica a gagné son premier Grammy pour un album thrash metal... dans la catégorie Best Metal Performance — les Grammys n'avaient pas de catégorie metal avant 1990."},
  {id:'mus27',cat:'music',text:"Le theremin, inventé en 1920, se joue sans le toucher — les mains du musicien modifient des champs électromagnétiques pour produire le son."},
  {id:'mus28',cat:'music',text:"Bob Marley a été enterré avec sa guitare Gibson Les Paul, un ballon de football, une Bible et une branche de marijuana."},
  {id:'mus29',cat:'music',text:"Le premier enregistrement sonore connu date de 1860 — un phonautogramme d'« Au clair de la lune » par Édouard-Léon Scott de Martinville."},
  {id:'mus30',cat:'music',text:"Hans Zimmer compose souvent ses bandes originales en commençant par une seule note — le « BWAAAA » d'Inception est devenu un cliché des bandes-annonces."},

  // ── WORLD (w21→w30) ──
  {id:'w21',cat:'world',text:"La Corée du Nord et la Finlande ne sont séparées que par un seul pays — la Russie, qui est si vaste qu'elle les relie."},
  {id:'w22',cat:'world',text:"Le Japon a plus de 6 800 îles, mais 421 seulement sont habitées — le reste est laissé à la nature."},
  {id:'w23',cat:'world',text:"La ville de Whittier en Alaska loge presque tous ses 300 habitants dans un seul immeuble — l'école, le commissariat et l'hôpital y sont aussi."},
  {id:'w24',cat:'world',text:"Il y a plus de pyramides au Soudan qu'en Égypte — environ 200 pyramides nubiennes contre 130 égyptiennes."},
  {id:'w25',cat:'world',text:"Le Vatican est le plus petit pays du monde avec 0,44 km² — mais il possède sa propre poste, radio et même une pharmacie."},
  {id:'w26',cat:'world',text:"Le lac Baïkal en Russie est si profond (1 642 m) qu'il contient à lui seul 20 % de l'eau douce non glacée de la planète."},
  {id:'w27',cat:'world',text:"L'Éthiopie a son propre calendrier avec 13 mois — elle a environ 7 ans de retard sur le calendrier grégorien."},
  {id:'w28',cat:'world',text:"Il existe un village en Norvège qui porte le nom de « Hell » — il gèle en hiver, ce qui donne littéralement « Hell freezes over »."},
  {id:'w29',cat:'world',text:"Les Pays-Bas sont si plats que leur point culminant, le Vaalserberg, ne fait que 322 mètres — certains immeubles sont plus hauts dans d'autres pays."},
  {id:'w30',cat:'world',text:"Le Bhoutan mesure son développement avec un indicateur de Bonheur National Brut plutôt que le PIB classique."},

  // ── MYTHOLOGY (myth21→myth30) ──
  {id:'myth21',cat:'mythology',text:"Cerbère, le chien à trois têtes, gardait les Enfers grecs — sa seule faiblesse connue était la musique, qui l'endormait."},
  {id:'myth22',cat:'mythology',text:"Dans la mythologie égyptienne, le Soleil est avalé chaque soir par la déesse Nout et renaît chaque matin de son ventre."},
  {id:'myth23',cat:'mythology',text:"Ragnarök, la fin du monde nordique, prévoit la mort de presque tous les dieux — mais aussi la renaissance d'un monde nouveau et vert."},
  {id:'myth24',cat:'mythology',text:"Le dieu Hermès a volé le troupeau d'Apollon le jour même de sa naissance — bébé, il a inventé la lyre pour se faire pardonner."},
  {id:'myth25',cat:'mythology',text:"Dans la mythologie polynésienne, Maui a pêché les îles du Pacifique hors de l'océan avec un hameçon magique."},
  {id:'myth26',cat:'mythology',text:"Le Minotaure ne mangeait que des jeunes Athéniens — sept garçons et sept filles envoyés en tribut tous les neuf ans."},
  {id:'myth27',cat:'mythology',text:"Icare n'est pas mort parce qu'il volait trop haut — il est aussi tombé parce que la cire fondait au soleil, mais son père Dédale a survécu."},
  {id:'myth28',cat:'mythology',text:"La déesse Kali en mythologie hindoue représente à la fois la destruction et la renaissance — elle porte un collier de crânes et danse sur Shiva."},
  {id:'myth29',cat:'mythology',text:"Les Valkyries nordiques ne choisissaient pas les plus forts au combat — elles choisissaient ceux qui devaient mourir pour rejoindre le Valhalla."},
  {id:'myth30',cat:'mythology',text:"Le Phénix renaît de ses cendres dans les mythologies égyptienne, grecque et chinoise — mais sous des formes très différentes."},

  // ── PSYCHOLOGY (psy21→psy30) ──
  {id:'psy21',cat:'psychology',text:"Le biais de confirmation pousse le cerveau à chercher uniquement les informations qui confirment ce qu'il croit déjà — et à ignorer le reste."},
  {id:'psy22',cat:'psychology',text:"Les gens surestiment systématiquement la durée de leurs émotions futures — c'est le biais d'impact, découvert par Daniel Gilbert."},
  {id:'psy23',cat:'psychology',text:"Le simple fait de sourire, même sans raison, peut activer des circuits neuronaux de bien-être — c'est l'hypothèse de la rétroaction faciale."},
  {id:'psy24',cat:'psychology',text:"Le syndrome de la page blanche n'est pas de la paresse — c'est un blocage créatif lié à la peur du jugement et au perfectionnisme."},
  {id:'psy25',cat:'psychology',text:"Les gens se souviennent mieux des tâches inachevées que des tâches terminées — c'est l'effet Zeigarnik, découvert en 1927."},
  {id:'psy26',cat:'psychology',text:"Le cerveau humain ne fait pas la différence entre un rejet social et une douleur physique — les mêmes zones cérébrales s'activent."},
  {id:'psy27',cat:'psychology',text:"La « paralysie du choix » est réelle : plus on a d'options, moins on est capable de décider — et moins on est satisfait de son choix final."},
  {id:'psy28',cat:'psychology',text:"Le « priming » montre que des mots ou images exposés brièvement influencent inconsciemment tes décisions suivantes."},
  {id:'psy29',cat:'psychology',text:"Les enfants bilingues développent une meilleure capacité d'attention sélective — leur cerveau s'entraîne à filtrer les informations en permanence."},
  {id:'psy30',cat:'psychology',text:"L'effet Barnum explique pourquoi les horoscopes semblent précis — le cerveau interprète les descriptions vagues comme personnelles."},

  // ── OCEANS (ocean21→ocean30) ──
  {id:'ocean21',cat:'oceans',text:"Les courants océaniques déplacent plus de chaleur que l'atmosphère — sans eux, l'Europe serait aussi froide que le Canada."},
  {id:'ocean22',cat:'oceans',text:"Le fond de l'océan est cartographié à seulement 25 % — on connaît mieux la surface de Mars que le plancher de nos propres mers."},
  {id:'ocean23',cat:'oceans',text:"Les récifs coralliens couvrent moins de 1 % du fond océanique mais abritent 25 % de toutes les espèces marines connues."},
  {id:'ocean24',cat:'oceans',text:"Le lac de saumure au fond du golfe du Mexique est un « lac dans l'océan » — si salé et dense que les poissons qui y entrent meurent de choc toxique."},
  {id:'ocean25',cat:'oceans',text:"Les vagues scélérates peuvent atteindre 30 mètres — leur existence a longtemps été considérée comme un mythe de marins."},
  {id:'ocean26',cat:'oceans',text:"L'océan Pacifique est si grand qu'il contient un point (le Pôle d'inaccessibilité) plus éloigné de toute terre que la Station spatiale internationale."},
  {id:'ocean27',cat:'oceans',text:"Les éponges marines sont les animaux les plus simples et les plus anciens — elles n'ont ni cerveau, ni cœur, ni muscles."},
  {id:'ocean28',cat:'oceans',text:"Le Gulf Stream transporte 30 fois plus d'eau que tous les fleuves du monde réunis — à une vitesse pouvant atteindre 9 km/h."},
  {id:'ocean29',cat:'oceans',text:"La bioluminescence dans l'océan est si courante que 76 % des créatures des profondeurs produisent leur propre lumière."},
  {id:'ocean30',cat:'oceans',text:"Le sel de tous les océans pourrait recouvrir la Terre entière d'une couche de 152 mètres d'épaisseur — un immeuble de 50 étages."},

  // ── RECORDS (rec21→rec30) ──
  {id:'rec21',cat:'records',text:"Le plus grand château de cartes jamais construit faisait 7,86 mètres de haut — l'œuvre de Bryan Berg, qui n'utilise ni colle ni ruban."},
  {id:'rec22',cat:'records',text:"Le plus long concert de l'histoire a duré 639 heures (26 jours), joué par un organiste qui se relayait toutes les quelques heures."},
  {id:'rec23',cat:'records',text:"La personne ayant détenu le plus de records Guinness simultanément est Ashrita Furman, avec plus de 600 records battus au total."},
  {id:'rec24',cat:'records',text:"Le plus grand nombre de personnes dans une Mini Cooper est de 28 — un record établi en 2014 par des étudiants au Royaume-Uni."},
  {id:'rec25',cat:'records',text:"Le plus rapide pour résoudre un Rubik's Cube est de 3,13 secondes — un record qui ne cesse de baisser chaque année."},
  {id:'rec26',cat:'records',text:"L'animal le plus rapide n'est pas le guépard mais le faucon pèlerin — il plonge à plus de 380 km/h en piqué."},
  {id:'rec27',cat:'records',text:"La plus longue distance parcourue en skateboard en 24 heures est de 501 km — par le Néo-Zélandais Andrew Andras."},
  {id:'rec28',cat:'records',text:"Le plus gros diamant jamais découvert est le Cullinan — 3 106 carats bruts, taillé en plusieurs pierres dont certaines ornent les joyaux de la couronne britannique."},
  {id:'rec29',cat:'records',text:"Le record de la plus longue distance en vol plané humain est de 764 km — établi par Klaus Ohlmann en Argentine en 2003."},
  {id:'rec30',cat:'records',text:"La plus haute vague jamais surfée mesure 26,21 mètres — par Sebastian Steudtner à Nazaré au Portugal en 2020."},

  // ── QUOTES (quote21→quote30) ──
  {id:'quote21',cat:'quotes',text:"Confucius a dit : « Celui qui déplace une montagne commence par déplacer de petites pierres. » Il enseignait il y a 2 500 ans."},
  {id:'quote22',cat:'quotes',text:"Nikola Tesla prédisait en 1926 : « Quand le sans-fil sera parfaitement appliqué, le monde entier sera converti en un immense cerveau. » Il décrivait le smartphone."},
  {id:'quote23',cat:'quotes',text:"Maya Angelou a écrit : « Les gens oublieront ce que tu as dit, oublieront ce que tu as fait, mais n'oublieront jamais ce que tu leur as fait ressentir. »"},
  {id:'quote24',cat:'quotes',text:"Darwin n'a jamais dit « Seuls les plus forts survivent » — il parlait des plus adaptés, ce qui est très différent."},
  {id:'quote25',cat:'quotes',text:"Picasso a dit : « Les bons artistes copient, les grands artistes volent. » Steve Jobs l'a ensuite cité pour justifier l'innovation chez Apple."},
  {id:'quote26',cat:'quotes',text:"Lao Tseu a écrit : « Un voyage de mille lieues commence par un pas. » Le Tao Te King est l'un des textes les plus traduits au monde."},
  {id:'quote27',cat:'quotes',text:"Hannah Arendt a théorisé la « banalité du mal » — l'idée que des gens ordinaires peuvent commettre des atrocités sans y voir de mal."},
  {id:'quote28',cat:'quotes',text:"« Après moi, le déluge » est attribuée à Louis XV ou Madame de Pompadour — elle reflète l'insouciance de la cour avant la Révolution."},
  {id:'quote29',cat:'quotes',text:"Hemingway a écrit : « Nous sommes tous brisés, c'est par là que la lumière entre. » Il pratiquait un style minimaliste devenu légendaire."},
  {id:'quote30',cat:'quotes',text:"Desmond Tutu a dit : « Si tu es neutre dans les situations d'injustice, tu as choisi le camp de l'oppresseur. » Il a reçu le Nobel de la Paix en 1984."},

  // ── LAWS (law21→law30) ──
  {id:'law21',cat:'laws',text:"En Thaïlande, sortir de chez soi sans sous-vêtements est techniquement illégal — même si la loi est rarement appliquée."},
  {id:'law22',cat:'laws',text:"En France, les boulangers n'ont pas le droit de prendre des vacances en même temps que le boulanger d'à côté — pour garantir le pain."},
  {id:'law23',cat:'laws',text:"À Milan, la loi oblige les citoyens à sourire en permanence dans les lieux publics — sous peine d'une amende théorique."},
  {id:'law24',cat:'laws',text:"En Oregon, il est interdit de chasser à dos de baleine — une loi improbable mais techniquement valide."},
  {id:'law25',cat:'laws',text:"Au Royaume-Uni, une loi de 1986 interdit de manipuler un saumon dans des circonstances suspectes — le Salmon Act, section 32."},
  {id:'law26',cat:'laws',text:"En Floride, si un éléphant est attaché à un parcmètre, son propriétaire doit payer le stationnement comme pour une voiture."},
  {id:'law27',cat:'laws',text:"Au Danemark, les parents doivent choisir un prénom sur une liste officielle de 7 000 prénoms approuvés par le gouvernement."},
  {id:'law28',cat:'laws',text:"En France, la loi interdit de prendre des photos de la Tour Eiffel illuminée la nuit sans autorisation — les jeux de lumière sont protégés par le droit d'auteur."},
  {id:'law29',cat:'laws',text:"Au Japon, être trop gros est techniquement une infraction : la loi Metabo oblige les entreprises à mesurer le tour de taille de leurs employés de plus de 40 ans."},
  {id:'law30',cat:'laws',text:"En Suisse, il est interdit de tondre sa pelouse le dimanche — le bruit est considéré comme une atteinte au repos dominical."},

  // ── TALES (tale21→tale30) ──
  {id:'tale21',cat:'tales',text:"La légende du vaisseau fantôme, le Hollandais Volant, raconte un navire condamné à errer éternellement sur les mers sans jamais accoster."},
  {id:'tale22',cat:'tales',text:"La légende du Wendigo, chez les Amérindiens Algonquins, parle d'un esprit de la famine qui transforme les humains en cannibales."},
  {id:'tale23',cat:'tales',text:"Le Basilic des légendes médiévales tuait d'un simple regard — seul le chant du coq ou un miroir pouvait le vaincre."},
  {id:'tale24',cat:'tales',text:"Dans les contes originaux, la Fée Clochette est jalouse, rancunière et tente de faire tuer Wendy — loin de la version Disney."},
  {id:'tale25',cat:'tales',text:"La légende du Kappa japonais décrit une créature aquatique qui noie les enfants — on l'apaise en s'inclinant, car elle doit rendre la politesse."},
  {id:'tale26',cat:'tales',text:"Le Rougarou, loup-garou cajun de Louisiane, est issu du loup-garou français importé par les colons acadiens."},
  {id:'tale27',cat:'tales',text:"La légende de la cité d'Ys en Bretagne raconte une ville engloutie par les flots — certains disent qu'elle est à l'origine du nom de Paris (Par-Ys)."},
  {id:'tale28',cat:'tales',text:"Le conte de Baba Yaga, sorcière slave, la décrit dans une maison sur pattes de poulet qui se déplace dans la forêt."},
  {id:'tale29',cat:'tales',text:"La légende du Bunyip australien aborigène décrit une créature des marais dont le cri terrifie quiconque l'entend — les colons pensaient que c'était un phoque."},
  {id:'tale30',cat:'tales',text:"Le conte original d'Aladin vient des Mille et Une Nuits mais se déroule en Chine — un détail souvent oublié."},

  // ── DINOSAURS (dino21→dino30) ──
  {id:'dino21',cat:'dinosaurs',text:"Le Therizinosaurus avait les plus longues griffes de tous les animaux connus — jusqu'à 1 mètre de long, probablement pour arracher des feuilles."},
  {id:'dino22',cat:'dinosaurs',text:"Les dinosaures avaient probablement des plumes colorées — des fossiles montrent des mélanosomes qui indiquent du rouge, du noir et même de l'irisé."},
  {id:'dino23',cat:'dinosaurs',text:"Le Pachycephalosaurus avait un crâne épais de 25 cm — les paléontologues débattent encore pour savoir s'il se battait en se cognant la tête."},
  {id:'dino24',cat:'dinosaurs',text:"Le Giganotosaurus, plus grand que le T-Rex, avait un cerveau en forme de banane et proportionnellement plus petit que celui d'un chat."},
  {id:'dino25',cat:'dinosaurs',text:"Les ptérosaures n'étaient pas des dinosaures — c'étaient des reptiles volants qui ont coexisté avec eux pendant 150 millions d'années."},
  {id:'dino26',cat:'dinosaurs',text:"Certains sauropodes avaient un « deuxième cerveau » dans la hanche — en réalité un amas de nerfs pour contrôler leur énorme queue."},
  {id:'dino27',cat:'dinosaurs',text:"L'extinction des dinosaures a aussi éliminé 75 % de toutes les espèces vivantes sur Terre — pas seulement les reptiles géants."},
  {id:'dino28',cat:'dinosaurs',text:"Le Dreadnoughtus, découvert en Argentine, est l'un des plus gros dinosaures dont on a retrouvé un squelette relativement complet — environ 65 tonnes."},
  {id:'dino29',cat:'dinosaurs',text:"Les dinosaures marins n'existaient pas — les plésiosaures et mosasaures étaient des reptiles marins, pas des dinosaures au sens scientifique."},
  {id:'dino30',cat:'dinosaurs',text:"Le Carnotaurus avait des bras encore plus petits que le T-Rex — à peine plus longs qu'une main humaine sur un corps de 8 mètres."}
];
